import { describe, it, expect } from 'vitest';
import {
  buildOneCsResult,
  deriveProductScore,
  deriveDataQualityScore,
  normalizeAdverseReasons,
  deriveOneCsStatus,
} from '../shared/oneCsScoring';

describe('ONE CS Scoring Algorithm', () => {
  const cases: Array<{
    label: string;
    creditScore: number | null;
    completenessScore: number;
    adverseReasons: string[];
  }> = [
    { label: '850 / perfect', creditScore: 850, completenessScore: 100, adverseReasons: [] },
    { label: '720 / delinquency+utilization', creditScore: 720, completenessScore: 85, adverseReasons: ['delinquency', 'high_utilization'] },
    { label: '650 / no reasons', creditScore: 650, completenessScore: 70, adverseReasons: [] },
    { label: '580 / serious+collections', creditScore: 580, completenessScore: 40, adverseReasons: ['serious_delinquency', 'collections'] },
    { label: 'null / thin file', creditScore: null, completenessScore: 10, adverseReasons: [] },
    { label: '300 / bankruptcy+no_file', creditScore: 300, completenessScore: 5, adverseReasons: ['bankruptcy', 'no_file'] },
    { label: '780 / thin_file', creditScore: 780, completenessScore: 90, adverseReasons: ['thin_file'] },
    { label: '720 / no reasons (bonus)', creditScore: 720, completenessScore: 85, adverseReasons: [] },
  ];

  cases.forEach(c => {
    it(c.label, () => {
      const r = buildOneCsResult(c.creditScore, c.completenessScore, c.adverseReasons, 'single', false);
      console.log(`${c.label} → productScore=${r.productScore} dqs=${r.dataQualityScore} status=${r.status}`);
      expect(r.productScore).toBeGreaterThan(0);
      expect(r.productScore).toBeLessThanOrEqual(20);
      expect(r.dataQualityScore).toBeGreaterThanOrEqual(1);
      expect(r.dataQualityScore).toBeLessThanOrEqual(10);
      expect(['success', 'review', 'decline', 'no_file']).toContain(r.status);
    });
  });

  it('deriveProductScore is linear 300→1 and 850→20', () => {
    expect(deriveProductScore(300)).toBe(1);
    expect(deriveProductScore(850)).toBe(20);
    expect(deriveProductScore(575)).toBeGreaterThan(1);
    expect(deriveProductScore(575)).toBeLessThan(20);
  });

  it('null credit score gives productScore=1', () => {
    expect(deriveProductScore(null)).toBe(1);
  });

  it('normalizeAdverseReasons deduplicates and maps', () => {
    const groups = normalizeAdverseReasons(['delinquency', 'DELINQUENCY', 'high_utilization']);
    expect(groups).toContain('delinquency');
    expect(groups).toContain('affordability');
  });

  it('no reasons + score >= 720 gives +0.3 bonus', () => {
    const r720 = buildOneCsResult(720, 85, [], 'single', false);
    const r719 = buildOneCsResult(719, 85, [], 'single', false);
    expect(r720.dataQualityScore).toBeGreaterThan(r719.dataQualityScore);
  });
});

import { describe, it, expect } from 'vitest';
import { parseImportedLeadText, toSafeImportedLeadRecord } from '../shared/importedLeadFormat';

describe('Lead Import + PII Masking', () => {
  it('parses multi-block raw text', () => {
    const raw = `John Doe, San Francisco CA 94102, 555-123-4567, john.doe@email.com
12/25/1985, SSN: 123-45-6789, Credit Score: 720

Jane Smith
123 Main St, New York NY 10001 | (212) 555-9876
jane@example.com | DOB: 03/15/1990 | Score: 650`;

    const blocks = parseImportedLeadText(raw);
    expect(blocks.length).toBeGreaterThanOrEqual(2);
  });

  it('masks PII in toSafeImportedLeadRecord', () => {
    const raw = `John Doe, San Francisco CA 94102, 555-123-4567, john.doe@email.com
12/25/1985, SSN: 123-45-6789, Credit Score: 720`;

    const blocks = parseImportedLeadText(raw);
    const safe = toSafeImportedLeadRecord(blocks[0]);

    console.log('Safe record:', JSON.stringify(safe, null, 2));

    // Name should be partially masked
    expect(safe.name).toMatch(/^J/); // first letter preserved
    expect(safe.name).not.toBe('John Doe');

    // SSN should be fully masked
    expect(safe.ssn).toBeNull();

    // Email should be null (no real email check needed)
    expect(safe.email).toBeNull();

    // Phone last 2 digits preserved
    expect(safe.phones[0]).toMatch(/..\*\d{2}$/);

    // normalizedTarget should be mock://
    expect(safe.normalizedTarget).toContain('mock://');
  });

  it('handles minimal input (score only)', () => {
    const blocks = parseImportedLeadText('Score: 750');
    expect(blocks.length).toBeGreaterThanOrEqual(1);
    const safe = toSafeImportedLeadRecord(blocks[0]);
    expect(safe.rawCreditScore).toBe(750);
  });

  it('handles null score', () => {
    const blocks = parseImportedLeadText('Name: Jane Doe, no credit score available');
    const safe = toSafeImportedLeadRecord(blocks[0]);
    expect(safe.rawCreditScore).toBeNull();
  });
});

