220	export function normalizeAdverseReasons(reasons: string[] = []) {
221	  const seenReasons = new Set<string>();
222	  const seenGroups = new Set<AdverseReasonGroup>();
223	  const normalizedReasons: string[] = [];
224	  const groups: AdverseReasonGroup[] = [];
225	
226	  for (const reason of reasons) {
227	    const normalized = normalizeAdverseReason(reason);
228	    if (!seenReasons.has(normalized.normalized)) {
229	      seenReasons.add(normalized.normalized);
230	      normalizedReasons.push(normalized.normalized);
231	    }
232	    if (normalized.group && !seenGroups.has(normalized.group)) {
233	      seenGroups.add(normalized.group);
234	      groups.push(normalized.group);
235	    }
236	  }
237	
238	  return {
239	    adverseReasons: normalizedReasons,
240	    adverseReasonGroups: groups,
241	  } as const;
242	}
