250	export function getBaseQualityFromCreditScore(creditScore: number | null) {
251	  if (creditScore == null) return 2.0;
252	  if (creditScore >= 850) return 10.0;
253	  if (creditScore >= 800) return 9.7;
254	  if (creditScore >= 760) return 9.0;
255	  if (creditScore >= 720) return 8.0;
256	  if (creditScore >= 680) return 7.4;
257	  if (creditScore >= 640) return 6.5;
258	  if (creditScore >= 600) return 5.5;
259	  if (creditScore >= 560) return 4.5;
260	  if (creditScore >= 520) return 3.5;
261	  if (creditScore >= 480) return 2.5;
262	  return 1.5;
