265	export function getCompletenessAdjustment(completenessScore: number | null | undefined) {
266	  const value = completenessScore ?? 0.65; // Unknown → assume medium-high completeness, no penalty
267	  if (value >= 0.95) return 0.8;
268	  if (value >= 0.8) return 0.5;
269	  if (value >= 0.65) return 0.2;
270	  if (value >= 0.5) return 0.0;
271	  if (value >= 0.35) return -0.3;
272	  return -0.8;
