275	export function derivePenaltyFromReasonGroups(groups: AdverseReasonGroup[]) {
276	  const total = groups.reduce((sum, group) => sum + GROUP_PENALTIES[group], 0);
277	  return Math.min(6.5, round1(total));
278	}
