280	export function deriveOneCsStatus(input: { creditScore: number | null; dataQualityScore: number; adverseReasonGroups: AdverseReasonGroup[] }) {
281	  if (input.creditScore == null && input.adverseReasonGroups.includes("no_file")) {
282	    return "no_file" satisfies OneCsStatus;
283	  }
284	  if (input.creditScore == null && input.adverseReasonGroups.length <= 1) {
285	    // Null score + few reasons = insufficient data, not decline
286	    return "review" satisfies OneCsStatus;
287	  }
288	  if (input.dataQualityScore >= 7.5) {
289	    return "success" satisfies OneCsStatus;
290	  }
291	  if (input.dataQualityScore >= 4.0) {
292	    return "review" satisfies OneCsStatus;
293	  }
294	  return "decline" satisfies OneCsStatus;
295	}
