297	export function buildOneCsExplanations(result: {
298	  creditScore: number | null;
299	  completenessScore?: number | null;
300	  adverseReasons: string[];
301	  adverseReasonGroups: AdverseReasonGroup[];
302	  productScore: number;
303	  dataQualityScore: number;
304	  status: OneCsStatus;
305	}) {
306	  const explanations: string[] = [];
307	
308	  if (result.creditScore == null) {
309	    explanations.push("Credit score was not found, so the profile starts from a low confidence baseline.");
310	  } else {
311	    explanations.push(`Raw credit score ${result.creditScore} mapped to product score ${result.productScore}/20.`);
312	  }
313	
314	  if (typeof result.completenessScore === "number") {
315	    explanations.push(`Record completeness contributed ${Math.round(result.completenessScore * 100)}% of the available lead signals.`);
316	  }
317	
318	  if (result.adverseReasonGroups.includes("public_record")) {
319	    explanations.push("Public record or collection signals materially reduced data quality.");
320	  }
321	  if (result.adverseReasonGroups.includes("delinquency")) {
322	    explanations.push("Recent or repeated delinquency pressure reduced the final score.");
323	  }
324	  if (result.adverseReasonGroups.includes("affordability")) {
325	    explanations.push("Income and debt affordability signals indicate lower financing readiness.");
326	  }
327	  if (result.adverseReasonGroups.includes("thin_file") || result.adverseReasonGroups.includes("low_depth")) {
328	    explanations.push("Thin or shallow credit history reduced confidence in profile stability.");
329	  }
330	  if (result.adverseReasonGroups.includes("utilization")) {
331	    explanations.push("High utilization or too many balances reduced quality despite other available signals.");
332	  }
333	  if (result.adverseReasonGroups.includes("inquiry_pressure")) {
334	    explanations.push("Recent inquiry pressure added a smaller negative adjustment.");
335	  }
336	  if (result.adverseReasons.length === 0 && (result.creditScore ?? 0) >= 720) {
337	    explanations.push("No adverse reasons were detected for a strong score band, so the profile received a small positive bonus.");
338	  }
339	
340	  explanations.push(`Final status: ${result.status}, data quality ${result.dataQualityScore}/10.`);
341	  return explanations;
342	}
