1	/**
2	 * Proxy Manager — ONE CS
3	 *
4	 * Алгоритм: минимум прокси — максимум результата
5	 *
6	 * Evomi — standard HTTP CONNECT proxy (не REST API):
7	 *   http://username:password@core-residential.evomi.com:1000
8	 * Sticky session управляется Evomi на их стороне.
9	 * Мы трекаем IP через тестовый GET на ipinfo.io/ip и считаем success-ротацию.
10	 *
11	 * Fallback: DataImpulse (REST API)
12	 *
13	 * Координация между воркерами: Redis SETNX mutex.
14	 * Без Redis — runtimeStore (in-process).
15	 */
16	
17	import { createHash, randomBytes } from "crypto";
18	import { ENV } from "./env";
19	import { saveRuntimeProxyLease } from "../runtimeStore";
20	
21	// === Constants ===
22	
23	const ROTATE_AFTER_N = parseInt(process.env.ROTATE_AFTER_N_SUCCESS ?? "20", 10);
24	const ROTATE_ON_ERRORS = parseInt(process.env.ROTATE_ON_ERROR_COUNT ?? "2", 10);
25	const EVOMI_HOST = ENV.evomiUsername ? "core-residential.evomi.com" : "";
26	const EVOMI_PORT = 1000;
27	const PROXY_TEST_URL = "https://api.ipify.org?format=text";
28	const PROXY_TEST_TIMEOUT_MS = 10_000;
29	const CIRCUIT_BREAKER_THRESHOLD = 5;
30	const CIRCUIT_BREAKER_RESET_MS = 60_000;
31	
32	// === Types ===
33	
34	export interface ProxyLease {
35	  leaseId: string;           // generated unique id (not Evomi session id since no API)
36	  provider: "evomi" | "dataimpulse";
37	  protocol: "http" | "socks5";
38	  host: string;               // proxy hostname
39	  port: number;               // proxy port
40	  username: string;
