  MOCK_PROXY_POLICIES,
  MOCK_PROXY_PROVIDERS,
  MOCK_SUBSCRIPTIONS,
  MOCK_WORKER_NODES,
} from "./platformMockData";
import {
  getRuntimeAdminByUsername,
  initRuntimeDefaultAdmin,
  saveRuntimeAdmin,
} from "./runtimeStore";
import {
  findRuntimeApiKeyByHash,
  findRuntimeJob,
  getRuntimeUsageSummary,
  listRuntimeApiKeys,
  listRuntimeAuditTrailEntries,
  listRuntimeBotTexts,
  listRuntimeJobEventsByJobId,
  listRuntimeJobs,
  listRuntimeTelegramRecipients,
  saveRuntimeApiKey,
  saveRuntimeAuditTrailEntry,
  saveRuntimeBotText,
  saveRuntimeJob,
  saveRuntimeJobEvents,
  saveRuntimeProxyLease,
  saveRuntimeUsageRecord,
  saveRuntimeWorkerRun,
  updateRuntimeApiKey,
  updateRuntimeJob,
} from "./runtimeStore";

let _db: ReturnType<typeof drizzle> | null = null;

type SubscriptionRow = {
  id: number;
  userId: number;
  planId: number;
  status: string;
  provider: string;
  externalRef: string | null;
  startedAt: Date | null;
  currentPeriodStart: Date | null;
  currentPeriodEnd: Date | null;
  canceledAt?: Date | null;

export const ENV = {
  // Server
  port: parseInt(process.env.PORT ?? "3000"),
  nodeEnv: process.env.NODE_ENV ?? "development",
  isProduction: process.env.NODE_ENV === "production",

