1	/**
2	 * fingerprintRotator.ts — Browser fingerprint generation.
3	 *
4	 * Generates a fresh, randomized FingerprintProfile for each request.
5	 * Converts to Playwright-compatible context options.
6	 *
7	 * Reference: legacy_research/extracted/credit_score_bot/cs_module/fingerprint/rotator.py
8	 */
9	
10	// ---------------------------------------------------------------------------
11	// Data pools for randomization
12	// ---------------------------------------------------------------------------
13	
14	const SCREEN_RESOLUTIONS: Array<[number, number]> = [
15	  [1366, 768], [1920, 1080], [1440, 900], [1536, 864],
16	  [1280, 800], [1600, 900], [1280, 1024], [1024, 768],
17	  [1680, 1050], [1920, 1200], [2560, 1440], [1360, 768],
18	];
19	
20	const TIMEZONES = [
21	  "America/New_York", "America/Chicago", "America/Denver",
22	  "America/Los_Angeles", "America/Phoenix", "America/Detroit",
23	  "America/Indiana/Indianapolis", "America/Boise",
24	  "America/Anchorage", "Pacific/Honolulu",
25	];
26	
27	const LANGUAGES: string[][] = [
28	  ["en-US", "en"],
29	  ["en-US", "en", "es"],
30	  ["en-US", "en-GB", "en"],
31	  ["en-US"],
32	];
33	
34	const PLATFORMS = ["Win32", "Win32", "Win32", "MacIntel", "Linux x86_64"];
35	
36	const CPU_CORES = [2, 4, 4, 4, 6, 8, 8, 12, 16];
37	
38	const DEVICE_MEMORY = [2, 4, 4, 8, 8, 16];
39	
40	const WEBGL_VENDORS: Array<[string, string]> = [
41	  [
42	    "Google Inc. (NVIDIA)",
43	    "ANGLE (NVIDIA, NVIDIA GeForce GTX 1060 6GB Direct3D11 vs_5_0 ps_5_0, D3D11)",
44	  ],
45	  [
46	    "Google Inc. (Intel)",
47	    "ANGLE (Intel, Intel(R) UHD Graphics 620 Direct3D11 vs_5_0 ps_5_0, D3D11)",
48	  ],
49	  [
50	    "Google Inc. (AMD)",
51	    "ANGLE (AMD, AMD Radeon RX 580 Direct3D11 vs_5_0 ps_5_0, D3D11)",
52	  ],
53	  [
54	    "Google Inc. (NVIDIA)",
55	    "ANGLE (NVIDIA, NVIDIA GeForce RTX 2060 Direct3D11 vs_5_0 ps_5_0, D3D11)",
56	  ],
57	  ["Intel Inc.", "Intel Iris OpenGL Engine"],
58	  ["Apple Inc.", "Apple GPU"],
59	];
60	
61	const FF_VERSIONS = [
62	  "115.0", "116.0", "117.0", "118.0", "119.0",
63	  "120.0", "121.0", "122.0", "123.0",
64	];
65	
66	const WIN_VERSIONS = [
67	  "Windows NT 10.0; Win64; x64",
68	  "Windows NT 10.0; WOW64",
69	  "Windows NT 6.1; Win64; x64",
70	];
71	
72	const MAC_VERSIONS = [
73	  "Macintosh; Intel Mac OS X 10.15",
74	  "Macintosh; Intel Mac OS X 11.0",
75	  "Macintosh; Intel Mac OS X 12.0",
76	  "Macintosh; Intel Mac OS X 13.0",
77	];
78	
79	// ---------------------------------------------------------------------------
80	// Types
81	// ---------------------------------------------------------------------------
82	
83	export interface FingerprintProfile {
84	  /** Full User-Agent string */
85	  userAgent: string;
86	  screenWidth: number;
87	  screenHeight: number;
88	  timezone: string;
89	  languages: string[];
90	  platform: string;
91	  hardwareConcurrency: number;
92	  deviceMemory: number;
93	  webglVendor: string;
94	  webglRenderer: string;
95	  canvasNoiseSeed: number;
96	  audioNoiseSeed: number;
97	  doNotTrack: string | null;
98	}
99	
100	// ---------------------------------------------------------------------------
101	// Helpers
102	// ---------------------------------------------------------------------------
103	
104	function pick<T>(arr: T[]): T {
105	  return arr[Math.floor(Math.random() * arr.length)];
106	}
107	
108	function randInt(min: number, max: number): number {
109	  return Math.floor(Math.random() * (max - min + 1)) + min;
110	}
111	
112	function buildFirefoxUserAgent(platform: string, ffVersion: string): string {
113	  let osStr: string;
114	  if (platform === "MacIntel") {
115	    osStr = pick(MAC_VERSIONS);
116	  } else if (platform === "Linux x86_64") {
117	    osStr = "X11; Linux x86_64";
118	  } else {
119	    osStr = pick(WIN_VERSIONS);
120	  }
121	  return `Mozilla/5.0 (${osStr}; rv:${ffVersion}) Gecko/20100101 Firefox/${ffVersion}`;
122	}
123	
124	// ---------------------------------------------------------------------------
125	// Rotator
126	// ---------------------------------------------------------------------------
127	
128	export class FingerprintRotator {
129	  /**
130	   * Generate a fresh, randomized FingerprintProfile.
131	   * Call `.generate()` to get a new profile for each browser request.
132	   */
133	  generate(): FingerprintProfile {
134	    const screen = pick(SCREEN_RESOLUTIONS);
135	    const tz = pick(TIMEZONES);
136	    const langs = pick(LANGUAGES);
137	    const platform = pick(PLATFORMS);
138	    const cores = pick(CPU_CORES);
139	    const mem = pick(DEVICE_MEMORY);
140	    const webgl = pick(WEBGL_VENDORS);
141	    const ffVer = pick(FF_VERSIONS);
142	    const userAgent = buildFirefoxUserAgent(platform, ffVer);
143	
144	    return {
145	      userAgent,
146	      screenWidth: screen[0],
147	      screenHeight: screen[1],
148	      timezone: tz,
149	      languages: langs,
150	      platform,
151	      hardwareConcurrency: cores,
152	      deviceMemory: mem,
153	      webglVendor: webgl[0],
154	      webglRenderer: webgl[1],
155	      canvasNoiseSeed: randInt(1, 999_999),
156	      audioNoiseSeed: randInt(1, 999_999),
157	      // Mostly no DNT (2/3 chance of null)
158	      doNotTrack: Math.random() < 0.33 ? "1" : null,
159	    };
160	  }
161	
162	  /**
163	   * Convert a FingerprintProfile to Playwright BrowserContext options.
164	   * Pass these to `browser.newContext(...)`.
165	   */
166	  toContextOptions(profile: FingerprintProfile): Record<string, unknown> {
167	    return {
168	      userAgent: profile.userAgent,
169	      viewport: {
170	        width: profile.screenWidth,
171	        height: profile.screenHeight,
172	      },
173	      locale: profile.languages[0] ?? "en-US",
174	      timezoneId: profile.timezone,
175	      extraHTTPHeaders: {
176	        "Accept-Language": [...profile.languages, "q=0.9"].join(",").replace("en-US,q=0.9", "en-US,en;q=0.9"),
177	        "DNT": profile.doNotTrack ?? "1",
178	      },
179	      // deviceScaleFactor and isMobile left unset — default desktop
180	    };
181	  }
182	
183	  /**
184	   * Return anti-detection launch arguments to pass to browser.newPage().
185	   * These are applied AFTER context creation and are passed as launch args
186	   * or via page.addInitScript.
187	   */
188	  getAntiDetectLaunchArgs(): string[] {
189	    return [
190	      "--disable-blink-features=AutomationControlled",
191	      "--no-sandbox",
192	      "--disable-dev-shm-usage",
193	      "--disable-gpu",
194	      "--disable-web-security",
195	      "--disable-features=IsolateOrigins,site-per-process",
196	    ];
197	  }
198	
199	  /**
200	   * Build an object with all WebGL spoofing parameters.
201	   * Use with page.addInitScript to inject into the page.
202	   */
203	  buildWebGlSpoof(profile: FingerprintProfile): {
204	    vendor: string;
205	    renderer: string;
206	  } {
207	    return {
208	      vendor: profile.webglVendor,
209	      renderer: profile.webglRenderer,
210	    };
211	  }
212	}
213	
214	/** Module-level singleton — prefer instantiating per-worker for isolation. */
215	export const defaultFingerprintRotator = new FingerprintRotator();
216

