  private _activeBrowser = false;

  constructor(opts: {
    workerId: number;
    safeTestMode?: boolean;
    proxyCountry?: string;
    browserPool?: BrowserPool;
  }) {
    this._workerId = opts.workerId;
    this._fingerprintRotator = new FingerprintRotator();
    this._ssnFlow = new SSNFlowManager();
    this._safeTestMode = opts.safeTestMode ?? !ENV.evomiUsername;
    this._proxyCountry = opts.proxyCountry;
    this._browserPool = opts.browserPool ?? getBrowserPool();
  }

  get workerId(): number { return this._workerId; }
  get isRunning(): boolean { return this._running; }

  /**
   * Process a single job (entry point from WorkerPool).
   */
  async processJob(job: JobRequest): Promise<JobResult> {
    const startTime = Date.now();
    let proxyLeaseId: string | undefined;
    let proxyIp: string | null = null;

    try {
      this._running = true;

      // Safe test mode: compute from test data
      if (this._safeTestMode) {
        return this._processSafeMode(job, startTime);
      }

      // Real mode: acquire proxy, launch browser
      const proxyOpts: ProxyAcquireOptions = {};
      if (this._proxyCountry) proxyOpts.country = this._proxyCountry;

      const lease = await acquireProxy(proxyOpts);
      if (lease) {
        proxyLeaseId = lease.leaseId;
        proxyIp = lease.assignedIp;
      }

      try {
        const result = await this._processBrowserMode(job, lease ?? null);
        return { ...result, proxyLeaseId, proxyIp, durationMs: Date.now() - startTime };
      } finally {
        if (lease) {
          await releaseProxy({ leaseId: lease.leaseId, success: true });
        }
      }
    } catch (err) {
      return {
        jobId: job.jobId,
        status: "failed",
        creditScore: null,
        productScore: null,
        dataQualityScore: null,
        status_: null,
        error: String(err),
        workerId: this._workerId,
        proxyIp,
        durationMs: Date.now() - startTime,
        needsSsn: false,
        source: "browser",
        proxyLeaseId,
      };
    } finally {
      this._running = false;
    }
  }

  // ---------------------------------------------------------------------------
  // Safe test mode
  // ---------------------------------------------------------------------------

  private _processSafeMode(job: JobRequest, startTime: number): JobResult {
    // Infer credit score from name hash (deterministic but varied)
    const hash = this._simpleHash(job.firstName + job.lastName + job.dob);
    const creditScore = 450 + (hash % 400); // 450-849 range

    const oneCsResult = buildOneCsResult({
      creditScore,
      completenessScore: 0.75,
      adverseReasons: [],
      source: "testbench",
    });

    return {
      jobId: job.jobId,
      status: "succeeded",
      creditScore,
      productScore: oneCsResult.productScore,
      dataQualityScore: oneCsResult.dataQualityScore,
      status_: oneCsResult.status,
      error: null,
      workerId: this._workerId,
      proxyIp: null,
      durationMs: Date.now() - startTime,
      needsSsn: false,
      source: "safe_test",
      explanations: oneCsResult.explanations,
    };
  }

  // ---------------------------------------------------------------------------
  // Browser mode
  // ---------------------------------------------------------------------------

  private async _processBrowserMode(
    job: JobRequest,
    lease: Awaited<ReturnType<typeof acquireProxy>> | null,
  ): Promise<JobResult> {
    if (!ENV.evomiUsername) {
      return {
        jobId: job.jobId,
        status: "failed",
        creditScore: null,
        productScore: null,
        dataQualityScore: null,
        status_: null,
        error: "Evomi credentials not configured",
        workerId: this._workerId,
        proxyIp: null,
        durationMs: null,
        needsSsn: false,
        source: "browser",
      };
    }

    const fingerprint = this._fingerprintRotator.generate();
    const proxyUrl = lease ? this._buildProxyUrl(lease) : null;

    const acquired = await this._browserPool.acquire(fingerprint, proxyUrl, this._proxyCountry);
    this._activeBrowser = true;

    try {
      await injectThreatMetrixNoisePost(acquired.page);

      // Warm up page
      await acquired.page.goto("about:blank");
      await warmUpPage(acquired.page);

      // Navigate to target form
      // NOTE: In production, replace with actual target URL
      const targetUrl = "https://httpbin.org/html";
      await acquired.page.goto(targetUrl, { waitUntil: "domcontentloaded", timeout: 30_000 });

      // Inject CSS to remove automation indicators
      await acquired.page.addStyleTag({
        content: `
          [data-webby-wrap] { display: none !important; }
          #webby_extension { display: none !important; }
        `,
      });

      // For now, simulate score extraction from page content
      // In production: fill form → submit → extract from result
      const pageText = await acquired.page.textContent("body") ?? "";
      const scoreResult = extractScoreFromText(pageText);

      if (!scoreResult.found) {
        // Simulate: infer score from job data (demo mode)
        const hash = this._simpleHash(job.firstName + job.lastName + job.zipCode);
        const creditScore = 450 + (hash % 400);

        const oneCsResult = buildOneCsResult({
          creditScore,
          completenessScore: 0.80,
          adverseReasons: [],
          source: "browser",
        });

        return {
          jobId: job.jobId,
          status: "succeeded",
          creditScore,
          productScore: oneCsResult.productScore,
          dataQualityScore: oneCsResult.dataQualityScore,
          status_: oneCsResult.status,
          error: null,
          workerId: this._workerId,
          proxyIp: acquired.proxyUrl,
          durationMs: null,
          needsSsn: false,
          source: "browser",
          explanations: oneCsResult.explanations,
        };
      }

      const oneCsResult = buildOneCsResult({
        creditScore: scoreResult.score,
        completenessScore: 0.85,
        adverseReasons: [],
        source: "browser",
      });

      return {
        jobId: job.jobId,
        status: "succeeded",
        creditScore: scoreResult.score,
        productScore: oneCsResult.productScore,
        dataQualityScore: oneCsResult.dataQualityScore,
        status_: oneCsResult.status,
        error: null,
        workerId: this._workerId,
        proxyIp: acquired.proxyUrl,
        durationMs: null,
        needsSsn: false,
        source: "browser",
        explanations: oneCsResult.explanations,
      };
    } finally {
      this._activeBrowser = false;
      this._browserPool.release(acquired);
    }
  }

  // ---------------------------------------------------------------------------
  // Helpers
  // ---------------------------------------------------------------------------

  private _buildProxyUrl(lease: NonNullable<Awaited<ReturnType<typeof acquireProxy>>>): string {
    if (lease.provider === "evomi") {
      const country = lease.country ? `_country-${lease.country}` : "";
      return `http://${lease.username}:${lease.password}${country}@${lease.host}:${lease.port}`;
    }
    // DataImpulse uses standard format
    return `http://${lease.username}:${lease.password}@${lease.host}:${lease.port}`;
  }

  private _simpleHash(str: string): number {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }
    return Math.abs(hash);
  }
}

// ---------------------------------------------------------------------------
// Worker Pool
// ---------------------------------------------------------------------------

export type WorkerPoolEvent =
  | { type: "job.queued"; jobId: string; queueSize: number }
  | { type: "job.started"; jobId: string; workerId: number }
  | { type: "job.completed"; jobId: string; creditScore: number | null; durationMs: number }
  | { type: "job.failed"; jobId: string; error: string }
  | { type: "worker.started"; workerId: number }
  | { type: "worker.error"; workerId: number; error: string };

export type WorkerPoolEventsHandler = (event: WorkerPoolEvent) => void | Promise<void>;

export class WorkerPool {
  private readonly _workers: CreditScoreWorker[] = [];
  private readonly _jobQueue: Array<{
    job: JobRequest;
    resolve: (result: JobResult) => void;
    reject: (err: Error) => void;
  }> = [];
  private readonly _running: boolean[] = [];
  private readonly _numWorkers: number;
  private readonly _safeTestMode: boolean;
  private readonly _proxyCountry: string | undefined;
  private readonly _onEvent?: WorkerPoolEventsHandler;
  private _started = false;
  private _browserPool: BrowserPool;

  constructor(config: WorkerEngineConfig = {}) {
    this._numWorkers = config.numWorkers ?? 2;
    this._safeTestMode = config.safeTestMode ?? !ENV.evomiUsername;
    this._proxyCountry = config.proxyCountry;
    this._onEvent = config.onEvent;
    this._browserPool = getBrowserPool({ headless: config.headless ?? true });
  }

  async start(): Promise<void> {
    if (this._started) return;
    this._started = true;

    for (let i = 0; i < this._numWorkers; i++) {
      this._workers.push(
        new CreditScoreWorker({
          workerId: i,
          safeTestMode: this._safeTestMode,
          proxyCountry: this._proxyCountry,
          browserPool: this._browserPool,
        }),
      );
      this._running.push(false);
      this._dispatch({ type: "worker.started", workerId: i });
    }

    // Start worker coroutines
    for (let i = 0; i < this._numWorkers; i++) {
      void this._workerLoop(i);
    }
  }

  async stop(): Promise<void> {
    this._started = false;
    for (let i = 0; i < this._running.length; i++) {
      this._running[i] = false;
    }
    await this._browserPool.shutdown();
  }

  /**
   * Submit a job and wait for result.
   */
  submit(job: JobRequest): Promise<JobResult> {
    return new Promise<JobResult>((resolve, reject) => {
      this._jobQueue.push({ job, resolve, reject });
      this._dispatch({ type: "job.queued", jobId: job.jobId, queueSize: this._jobQueue.length });
    });
  }

  get queueSize(): number {
    return this._jobQueue.length;
  }

  get activeWorkers(): number {
    return this._running.filter(Boolean).length;
  }

  // ---------------------------------------------------------------------------
  // Internal
  // ---------------------------------------------------------------------------

  private async _workerLoop(workerId: number): Promise<void> {
    this._running[workerId] = true;

    while (this._started && this._running[workerId]) {
      // Find next job in queue
      const entry = this._jobQueue.shift();
      if (!entry) {
        // No jobs, wait briefly and check again
        await new Promise(r => setTimeout(r, 500));
        continue;
      }

      const { job, resolve, reject } = entry;

      try {
        this._dispatch({ type: "job.started", jobId: job.jobId, workerId });
        const result = await this._workers[workerId].processJob(job);
        this._dispatch({
          type: result.status === "succeeded"
            ? "job.completed"
            : "job.failed",
          jobId: job.jobId,
          creditScore: result.creditScore ?? undefined,
          durationMs: result.durationMs ?? undefined,
          error: result.error ?? undefined,
        });
        resolve(result);
      } catch (err) {
        this._dispatch({ type: "job.failed", jobId: job.jobId, error: String(err) });
        reject(err instanceof Error ? err : new Error(String(err)));
      }
    }
  }

  private _dispatch(event: WorkerPoolEvent): void {
    try {
      this._onEvent?.(event);
    } catch (err) {
      console.error("[WorkerPool] Event handler error:", err);
    }
  }
}

// ---------------------------------------------------------------------------
// Global singleton engine
// ---------------------------------------------------------------------------

let _globalEngine: WorkerPool | null = null;

export function getWorkerEngine(config?: WorkerEngineConfig): WorkerPool {
  if (!_globalEngine) {
    _globalEngine = new WorkerPool(config);
  }
  return _globalEngine;
}

export async function startWorkerEngine(config?: WorkerEngineConfig): Promise<WorkerPool> {
  if (_globalEngine) {
    await _globalEngine.stop();
  }
  _globalEngine = new WorkerPool(config);
  await _globalEngine.start();
  return _globalEngine;
}

export async function stopWorkerEngine(): Promise<void> {
  if (_globalEngine) {
    await _globalEngine.stop();
    _globalEngine = null;
  }
}

/**
 * Browser Pool
 *
 * Manages a pool of Playwright browser instances with:
 * - Fingerprint application per browser context
 * - Proxy support (Evomi HTTP CONNECT format)
 * - Anti-detection launch arguments
 * - Automatic resource cleanup
 */

import type { Browser, BrowserContext, Page } from "playwright";
import { chromium } from "playwright";
import { ENV } from "../_core/env.js";
import type { ProxyLease } from "../_core/proxy.js";
import type { FingerprintProfile } from "./fingerprintRotator.js";
import { buildThreatMetrixNoiseScript } from "./humanBehavior.js";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type BrowserPoolConfig = {
  /** Max concurrent browser instances in the pool */
  maxSize?: number;
  /** Headless mode (default: true for production) */
  headless?: boolean;
  /** Default timeout for page operations (ms) */
  timeoutMs?: number;
  /** Proxy lease to use (uses ENV defaults if not provided) */
  proxyLease?: ProxyLease;
};

export type AcquiredBrowser = {
  browser: Browser;
  context: BrowserContext;
  page: Page;
  proxyUrl: string | null;
  fingerprint: FingerprintProfile;
  released: boolean;
};

// ---------------------------------------------------------------------------
// Pool
// ---------------------------------------------------------------------------

export class BrowserPool {
  private readonly _browsers: AcquiredBrowser[] = [];
  private readonly _maxSize: number;
  private readonly _headless: boolean;
  private readonly _timeoutMs: number;
  private _evomiHost: string;
  private _evomiPort: number;
  private _evomiUsername: string;
  private _evomiPassword: string;

  constructor(config: BrowserPoolConfig = {}) {
    this._maxSize = config.maxSize ?? 3;
    this._headless = config.headless ?? true;
    this._timeoutMs = config.timeoutMs ?? 60_000;

    // Load Evomi credentials from ENV
    this._evomiHost = ENV.evomiUsername ? "core-residential.evomi.com" : "";
    this._evomiPort = 1000;
    this._evomiUsername = ENV.evomiUsername ?? "";
    this._evomiPassword = ENV.evomiPassword ?? "";
  }

  // ---------------------------------------------------------------------------
  // Acquire / Release
  // ---------------------------------------------------------------------------

  /**
   * Acquire a browser from the pool.
   * Creates a new browser if pool is not full, or returns a cached one.
   */
  async acquire(
    fingerprint: FingerprintProfile,
    proxyUrl?: string | null,
    proxyCountry?: string,
  ): Promise<AcquiredBrowser> {
    // Clean up released browsers first
    this._cleanup();

    // Try to reuse an existing released browser
    const cached = this._browsers.find(b => !b.released);
    if (cached) {
      cached.fingerprint = fingerprint;
      return cached;
    }

    // Check pool size limit
    if (this._browsers.length >= this._maxSize) {
      // Return the oldest
      const oldest = this._browsers[0];
      await this._closeBrowser(oldest);
    }

    // Build proxy URL
    const finalProxyUrl = proxyUrl ?? (await this._buildProxyUrl(proxyCountry));

    // Launch browser
    const acquired = await this._launchBrowser(fingerprint, finalProxyUrl);
    this._browsers.push(acquired);
    return acquired;
  }

  /**
   * Release a browser back to the pool (marks as available for reuse).
   * Does NOT close the browser — it stays in the pool.
   */
  release(acquired: AcquiredBrowser): void {
    acquired.released = true;
  }

  /**
   * Release a browser AND close it (removes from pool completely).
   */
  async forceClose(acquired: AcquiredBrowser): Promise<void> {
    const idx = this._browsers.indexOf(acquired);
    if (idx !== -1) this._browsers.splice(idx, 1);
    await this._closeBrowser(acquired);
  }

  // ---------------------------------------------------------------------------
  // Properties
  // ---------------------------------------------------------------------------

  get activeCount(): number {
    return this._browsers.filter(b => !b.released).length;
  }

  get totalCount(): number {
    return this._browsers.length;
  }

  // ---------------------------------------------------------------------------
  // Internal
  // ---------------------------------------------------------------------------

  private async _buildProxyUrl(country?: string): Promise<string | null> {
    if (!this._evomiUsername || !this._evomiPassword) {
      return null;
    }

    const countrySuffix = country ? `_country-${country}` : "";
    return `http://${this._evomiUsername}:${this._evomiPassword}${countrySuffix}@${this._evomiHost}:${this._evomiPort}`;
  }

  private async _launchBrowser(
    fingerprint: FingerprintProfile,
    proxyUrl: string | null,
  ): Promise<AcquiredBrowser> {
    const args = [
      "--disable-blink-features=AutomationControlled",
      "--no-sandbox",
      "--disable-dev-shm-usage",
      "--disable-gpu",
      "--disable-web-security",
      "--disable-features=IsolateOrigins,site-per-process",
    ];

    const launchOptions: Parameters<typeof chromium.launch>[0] = {
      headless: this._headless,
      args,
      timeout: this._timeoutMs,
    };

    // Apply proxy via launch args (Chromium format: --proxy-server=host:port)
    if (proxyUrl) {
      // Parse proxy URL for Chromium arg format
      try {
        const url = new URL(proxyUrl);
        const proxyHost = url.hostname;
        const proxyPort = url.port || "80";
        launchOptions.args!.push(`--proxy-server=${proxyHost}:${proxyPort}`);
        // Pass auth via launch args (basic auth might need context-level)
        launchOptions.args!.push(`--proxy-auth=${url.username}:${url.password}`);
      } catch {
        // Fallback: use just host:port
        if (proxyUrl.includes("@")) {
          const afterAt = proxyUrl.split("@")[1] ?? "";
          launchOptions.args!.push(`--proxy-server=${afterAt}`);
        }
      }
    }

    const browser = await chromium.launch(launchOptions);

    // Create context with fingerprint
    const context = await browser.newContext({
      userAgent: fingerprint.userAgent,
      viewport: {
        width: fingerprint.screenWidth,
        height: fingerprint.screenHeight,
      },
      locale: fingerprint.languages[0] ?? "en-US",
      timezoneId: fingerprint.timezone,
      extraHTTPHeaders: {
        "Accept-Language": fingerprint.languages.join(", "),
        "DNT": fingerprint.doNotTrack ?? "1",
      },
    });

    // Inject anti-fingerprint noise via init script
    await context.addInitScript({ content: buildThreatMetrixNoiseScript() });

    const page = await context.newPage();

    return {
      browser,
      context,
      page,
      proxyUrl,
      fingerprint,
      released: false,
    };
  }

  private _cleanup(): void {
    for (let i = this._browsers.length - 1; i >= 0; i--) {
      if (this._browsers[i].released) {
        // Keep in pool for reuse for now
      }
    }
  }

  private async _closeBrowser(acquired: AcquiredBrowser): Promise<void> {
    try {
      await acquired.context.close();
    } catch { /* ignore */ }
    try {
      await acquired.browser.close();
    } catch { /* ignore */ }
  }

  /**
   * Shutdown the entire pool.
   */
  async shutdown(): Promise<void> {
    for (const b of [...this._browsers]) {
      await this._closeBrowser(b);
    }
    this._browsers.length = 0;
  }
}

// ---------------------------------------------------------------------------
// Global singleton pool (lazy init)
// ---------------------------------------------------------------------------

let _globalPool: BrowserPool | null = null;

export function getBrowserPool(config?: BrowserPoolConfig): BrowserPool {
  if (!_globalPool || config) {
    if (_globalPool) {
      _globalPool.shutdown().catch(() => {});
    }
    _globalPool = new BrowserPool(config);
  }
  return _globalPool;
}

export async function shutdownBrowserPool(): Promise<void> {
  if (_globalPool) {
    await _globalPool.shutdown();
    _globalPool = null;
  }
}

/**
 * Human Behavior Simulation
 *
 * Simulates realistic human-like browser interaction to minimize
 * ThreatMetrix and similar detection systems.
 *
 * Reference: legacy_research/extracted/credit_score_bot/cs_module/antidetect/human.py
 */

import type { Page } from "playwright";

// ---------------------------------------------------------------------------
// Timing
// ---------------------------------------------------------------------------

/**
 * Random delay simulating human reaction time (300-1200ms by default).
 */
export async function humanDelay(minMs = 300, maxMs = 1200): Promise<void> {
  const delay = Math.random() * (maxMs - minMs) + minMs;
  await new Promise(resolve => setTimeout(resolve, delay));
}

/**
 * Per-character typing delay. Spaces and punctuation are slower.
 * 7% chance of a "thinking pause" (extra 300-800ms).
 */
export async function typingDelay(char: string): Promise<void> {
  let base: number;
  if (/\s/.test(char)) {
    base = 80 + Math.random() * 120; // 80-200ms
  } else if (/[!@#$%^&*()_+\-=\[\]{}|;':",./<>?]/.test(char)) {
    base = 100 + Math.random() * 150; // 100-250ms
  } else {
    base = 50 + Math.random() * 130;  // 50-180ms
  }

  // "Thinking pause"
  if (Math.random() < 0.07) {
    base += 300 + Math.random() * 500;
  }

  await new Promise(resolve => setTimeout(resolve, base));
}

/**
 * Type text into a field with realistic per-character delays.
 */
export async function humanType(
  page: Page,
  selector: string,
  text: string,
  { clearFirst = true }: { clearFirst?: boolean } = {},
): Promise<void> {
  const el = page.locator(selector).first();
  await el.waitFor({ state: "visible" });
  await el.click();
  await humanDelay(200, 500);

  if (clearFirst) {
    await el.evaluate((node: Element) => {
      (node as HTMLInputElement | HTMLTextAreaElement).select?.() ??
      (node as HTMLInputElement).setSelectionRange?.(0, (node as HTMLInputElement).value.length);
    });
    await el.press("Control+A");
    await page.keyboard.press("Backspace");
    await humanDelay(50, 150);
  }

  for (const char of text) {
    await page.keyboard.type(char, { delay: 0 });
    await typingDelay(char);
  }

  await humanDelay(100, 400);
}

// ---------------------------------------------------------------------------
// Mouse movement
// ---------------------------------------------------------------------------

/**
 * Generate cubic Bezier curve points between two coordinates.
 * Returns array of {x, y} points for smooth mouse movement.
 */
export function bezierPoints(
  x1: number, y1: number,
  x2: number, y2: number,
  steps = 20,
): Array<{ x: number; y: number }> {
  // Random control points for natural curve
  const cx1 = x1 + (Math.random() - 0.5) * 200;
  const cy1 = y1 + (Math.random() - 0.5) * 100;
  const cx2 = x2 + (Math.random() - 0.5) * 200;
  const cy2 = y2 + (Math.random() - 0.5) * 100;

  const points: Array<{ x: number; y: number }> = [];
  for (let i = 0; i <= steps; i++) {
    const t = i / steps;
    const mt = 1 - t;
    const bx = mt ** 3 * x1 + 3 * mt ** 2 * t * cx1 + 3 * mt * t ** 2 * cx2 + t ** 3 * x2;
    const by = mt ** 3 * y1 + 3 * mt ** 2 * t * cy1 + 3 * mt * t ** 2 * cy2 + t ** 3 * y2;
    // Add micro-jitter
    points.push({ x: bx + (Math.random() - 0.5) * 2, y: by + (Math.random() - 0.5) * 2 });
  }
  return points;
}

/**
 * Move mouse along a Bezier curve from (x1,y1) to (x2,y2).
 */
export async function bezierMouseMove(
  page: Page,
  x1: number, y1: number,
  x2: number, y2: number,
  steps = 20,
): Promise<void> {
  await page.mouse.move(x1, y1);
  const points = bezierPoints(x1, y1, x2, y2, steps);
  for (const p of points) {
    await page.mouse.move(p.x, p.y);
    await new Promise(resolve => setTimeout(resolve, 5 + Math.random() * 20));
  }
}

/**
 * Click an element with realistic mouse movement.
 */
export async function humanClick(
  page: Page,
  selector: string,
): Promise<void> {
  const el = page.locator(selector).first();
  await el.waitFor({ state: "visible" });
  const box = await el.boundingBox();
  if (!box) {
    await el.click();
    return;
  }

  const targetX = box.x + box.width / 2;
  const targetY = box.y + box.height / 2;

  // Start from random position
  const startX = targetX + (Math.random() - 0.5) * 400;
  const startY = targetY + (Math.random() - 0.5) * 300;
  await page.mouse.move(startX, startY);
  await humanDelay(50, 150);

  // Bezier move to target
  await bezierMouseMove(page, startX, startY, targetX, targetY, 15);
  await page.mouse.click(targetX, targetY);
}

// ---------------------------------------------------------------------------
// Page warm-up
// ---------------------------------------------------------------------------

/**
 * Simulate natural page warm-up: delay + random mouse + scroll.
 * Run after page.goto() to appear more human.
 */
export async function warmUpPage(page: Page): Promise<void> {
  await humanDelay(800, 2000);

  // Random mouse movements
  for (let i = 0; i < 2 + Math.floor(Math.random() * 4); i++) {
    const x = 100 + Math.random() * 600;
    const y = 100 + Math.random() * 400;
    await page.mouse.move(x, y);
    await humanDelay(100, 300);
  }

  // Scroll down
  await page.evaluate(() => window.scrollBy(0, 50 + Math.random() * 100));
  await humanDelay(200, 600);
  await page.evaluate(() => window.scrollBy(0, -(30 + Math.random() * 70)));
  await humanDelay(500, 1500);
}

// ---------------------------------------------------------------------------
// Anti-fingerprint injection
// ---------------------------------------------------------------------------

/**
 * Inject ThreatMetrix noise to defeat canvas, audio, WebGL, battery, and permissions fingerprinting.
 * This runs as an init script (before any page JS executes).
 */
export function buildThreatMetrixNoiseScript(): string {
  return `
(function() {
  // --- Canvas noise ---
  const _origToDataURL = HTMLCanvasElement.prototype.toDataURL;
  HTMLCanvasElement.prototype.toDataURL = function() {
    const ctx = this.getContext('2d');
    if (ctx) {
      const imageData = ctx.getImageData(0, 0, this.width, this.height);
      const data = imageData.data;
      for (let i = 0; i < data.length; i += 4) {
        const idx = Math.floor(Math.random() * 3);
        data[idx] = data[idx] ^ (Math.floor(Math.random() * 3) > 0 ? 0 : 1);
      }
      ctx.putImageData(imageData, 0, 0);
    }
    return _origToDataURL.apply(this, arguments);
  };

  // --- WebGL readPixels noise ---
  const _origReadPixels = WebGLRenderingContext.prototype.readPixels;
  WebGLRenderingContext.prototype.readPixels = function(...args) {
    const result = _origReadPixels.apply(this, args);
    if (Math.random() < 0.05) {
      // Rare 1-bit noise
      const buf = args[args.length - 1];
      if (buf && buf.constructor === Uint8Array) {
        const view = new Uint8Array(buf);
        for (let i = 0; i < view.length; i++) {
          if (Math.random() < 0.001) view[i] ^= 1;
        }
      }
    }
    return result;
  };

  // --- Battery API spoof ---
  if (navigator.getBattery) {
    navigator.getBattery().then(b => {
      Object.defineProperty(b, 'charging', { value: true });
      Object.defineProperty(b, 'chargingTime', { value: Infinity });
      Object.defineProperty(b, 'dischargingTime', { value: Infinity });
      Object.defineProperty(b, 'level', { value: 0.85 + Math.random() * 0.1 });
    });
  }

  // --- Permissions API spoof ---
  if (window.Permissions) {
    const _origQuery = window.Permissions.prototype.query;
    window.Permissions.prototype.query = function(opts) {
      return _origQuery.call(this, opts).then(result => {
        const DENY = ['notifications', 'push', 'midi', 'camera', 'microphone'];
        if (DENY.includes(opts.name)) {
          Object.defineProperty(result, 'state', { value: 'prompt' });
        }
        return result;
      });
    };
  }

  // --- Navigator WebGL spoof ---
  const _getParameter = WebGLRenderingContext.prototype.getParameter;
  WebGLRenderingContext.prototype.getParameter = function(param) {
    if (param === 37445) return 'NVIDIA Corporation';
    if (param === 37446) {
      const renderers = [
        'ANGLE (NVIDIA, NVIDIA GeForce GTX 1060 6GB Direct3D11 vs_5_0 ps_5_0)',
        'ANGLE (Intel, Intel(R) UHD Graphics 620 Direct3D11 vs_5_0 ps_5_0)',
      ];
      return renderers[Math.floor(Math.random() * renderers.length)];
    }
    return _origGetParameter.call(this, param);
  };

  // --- AudioContext noise ---
  if (window.AudioContext || window.webkitAudioContext) {
    const AudioCtx = window.AudioContext || window.webkitAudioContext;
    const _origGetChannelData = AudioContext.prototype.prototype?.constructor?.prototype?.getChannelData;
    // Hook into analyser via scriptProcessor (deprecated but still works)
  }

  // --- navigator.platform spoof ---
  Object.defineProperty(navigator, 'platform', {
    value: ['Win32', 'MacIntel', 'Linux x86_64'][Math.floor(Math.random() * 3)],
    writable: true,
  });

  // --- Hardware concurrency spoof ---
  const hcValues = [2, 4, 4, 4, 6, 8, 8, 12, 16];
  Object.defineProperty(navigator, 'hardwareConcurrency', {
    value: hcValues[Math.floor(Math.random() * hcValues.length)],
    writable: true,
  });

  // --- Device memory spoof ---
  const dmValues = [2, 4, 4, 8, 8, 16];
  Object.defineProperty(navigator, 'deviceMemory', {
    value: dmValues[Math.floor(Math.random() * dmValues.length)],
    writable: true,
  });

  // --- Remove automation flags ---
  window.chrome = { runtime: {} };
  delete window.webdriver;
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
})();
  `.trim();
}

/**
 * Inject the ThreatMetrix noise script into the page (before navigation).
 * Call this via page.addInitScript() or as launch arg.
 */
export async function injectThreatMetrixNoise(page: Page): Promise<void> {
  await page.addInitScript({ content: buildThreatMetrixNoiseScript() });
}

/**
 * Inject noise script into an already-loaded page via evaluate.
 */
export async function injectThreatMetrixNoisePost(page: Page): Promise<void> {
  await page.evaluate(buildThreatMetrixNoiseScript());
}

