256	/**
257	 * Validates and normalizes a SSN string to xxx-xx-xxxx format.
258	 * Returns null if the SSN is invalid.
259	 */
260	export function validateSsn(raw: string): string | null {
261	  if (!raw || typeof raw !== "string") return null;
262	  const digits = raw.replace(/[-\s]/g, "").replace(/\D/g, "");
263	  if (digits.length !== 9) return null;
264	
265	  const area = parseInt(digits.slice(0, 3), 10);
266	  const group = parseInt(digits.slice(3, 5), 10);
267	  const serial = parseInt(digits.slice(5, 9), 10);
268	
269	  if (area === 0 || area === 666 || area >= 900) return null;
270	  if (group === 0) return null;
271	  if (serial === 0) return null;
272	
273	  return `${digits.slice(0, 3)}-${digits.slice(3, 5)}-${digits.slice(5)}`;
274	}
