327	/**
328	 * Extracts credit score from adverse action text content.
329	 * Supports multiple regex patterns and null-score cases.
330	 */
331	export function extractScoreFromText(content: string): number | null {
332	  if (!content || typeof content !== "string") return null;
333	  const text = content.toLowerCase().trim();
334	
335	  const nullPatterns = [
336	    /no\s*(credit\s*)?(history|file|profile|record)/i,
337	    /unable\s*to\s*find\s*(credit\s*)?(profile|record|file)/i,
338	    /no\s*file/i,
339	    /no\s*information\s*available/i,
340	    /insufficient\s*(credit\s*)?(data|history|information)/i,
341	    /not\s*(enough|sufficient)\s*credit/i,
342	    /thin\s*file/i,
343	    /no\s*score/i,
344	  ];
345	
346	  for (const pattern of nullPatterns) {
347	    if (pattern.test(text)) return null;
348	  }
349	
350	  const scorePatterns = [
351	    /credit\s*score\s*(?:is|:|\b)\s*(\d{3})/i,
352	    /(?:your\s+)?score\s*(?:is|:|\s+of\s+)\s*(\d{3})/i,
353	    /FICO[\s:]*(\d{3})/i,
354	    /VantageScore[\s:]*(\d{3})/i,
355	    /rating\s*(?:is|:|of)\s*(\d{1,2})\b/i,
356	    /score\s*value\s*[:\-=]\s*(\d{3})/i,
357	    /(?:current|latest|actual)\s*score\s*[:\-=]\s*(\d{3})/i,
358	    /(?:result|resulting)\s*score\s*[=:]\s*(\d{3})/i,
359	    /score\s*[:\-]\s*(\d{3})/i,
360	  ];
361	
362	  for (const pattern of scorePatterns) {
363	    const match = text.match(pattern);
364	    if (match) {
365	      const rawVal = parseInt(match[1], 10);
366	      if (rawVal > 850) continue;
367	      if (rawVal <= 10) {
368	        return Math.round(300 + (rawVal - 1) * 61);
369	      }
370	      if (rawVal >= 300 && rawVal <= 850) return rawVal;
371	    }
372	  }
373	
374	  return null;
375	}
