377	/**
378	 * Extracts score from a user_attachment/extracted/ved/txt/ directory.
379	 */
380	export function extractScoreFromVedDirectory(dirPath: string): Promise<number | null> {
381	  const fs = require("fs") as typeof import("fs");
382	  const path = require("path") as typeof import("path");
383	  if (!fs.existsSync(dirPath)) return Promise.resolve(null);
384	  try {
385	    const files = fs.readdirSync(dirPath).filter(f => f.endsWith(".txt"));
386	    for (const file of files.sort()) {
387	      const filePath = path.join(dirPath, file);
388	      const content = fs.readFileSync(filePath, "utf8");
389	      const score = extractScoreFromText(content);
390	      if (score !== null) return Promise.resolve(score);
391	    }
392	  } catch { return Promise.resolve(null); }
393	  return Promise.resolve(null);
394	}
