399	
400	export interface Point { x: number; y: number; }
401	export interface BezierCurve { points: Point[]; durationMs: number; }
402	
403	/**
404	 * Generates a smooth cubic bezier path between two points.
405	 */
406	export function generateBezierPath(from: Point, to: Point, curvatureFactor = 0.3): BezierCurve {
407	  const dx = to.x - from.x;
408	  const dy = to.y - from.y;
409	  const dist = Math.sqrt(dx * dx + dy * dy) || 1;
410	
411	  const perpX = -dy / dist;
412	  const perpY = dx / dist;
413	  const magnitude = dist * curvatureFactor;
414	  const perturbX = (Math.random() - 0.5) * magnitude * 0.5;
415	  const perturbY = (Math.random() - 0.5) * magnitude * 0.5;
416	
417	  const cp1x = from.x + dx * 0.33 + (perpX * magnitude + perturbX);
418	  const cp1y = from.y + dy * 0.33 + (perpY * magnitude + perturbY);
419	  const cp2x = from.x + dx * 0.66 - (perpX * magnitude - perturbX);
420	  const cp2y = from.y + dy * 0.66 - (perpY * magnitude - perturbY);
421	
422	  const numSamples = Math.max(8, Math.ceil(dist / 20));
423	  const points: Point[] = [];
424	
425	  for (let i = 0; i <= numSamples; i++) {
426	    const t = i / numSamples;
427	    const mt = 1 - t;
428	    const t2 = t * t;
429	    const mt2 = mt * mt;
430	    const t3 = t2 * t;
431	    const mt3 = mt2 * mt;
432	
433	    points.push({
434	      x: mt3 * from.x + 3 * mt2 * t * cp1x + 3 * mt * t2 * cp2x + t3 * to.x,
435	      y: mt3 * from.y + 3 * mt2 * t * cp1y + 3 * mt * t2 * cp2y + t3 * to.y,
436	    });
437	  }
438	
439	  const durationMs = Math.round(300 + dist * 1.2 + Math.random() * 300);
440	  return { points, durationMs };
441	}
442	
443	export function calculateHumanDelay(baseMs = 50, jitterMs = 70): number {
444	  return baseMs + Math.floor(Math.random() * jitterMs);
445	}
446	
447	export function generateHumanMousePath(steps: Array<{ action: "move" | "click" | "type"; to: Point }>): BezierCurve[] {
448	  const curves: BezierCurve[] = [];
449	  let currentPoint: Point = { x: 0, y: 0 };
450	  for (const step of steps) {
451	    const curve = generateBezierPath(currentPoint, step.to);
452	    curves.push(curve);
453	    currentPoint = step.to;
454	    if (step.action === "click" || step.action === "type") {
455	      curves.push({ points: [step.to, step.to], durationMs: calculateHumanDelay(80, 120) });
456	    }
457	  }
458	  return curves;
459	}
460	
461	export function calculateTotalHumanTime(curves: BezierCurve[]): number {
462	  return curves.reduce((sum, c) => sum + c.durationMs, 0);
463	}
