469	export class WorkerPool {
470	  private workers = new Map<string, WorkerInstance>();
471	  private options: Required<WorkerPoolOptions>;
472	
473	  constructor(options: Partial<WorkerPoolOptions> = {}) {
474	    this.options = {
475	      maxWorkers: options.maxWorkers ?? 4,
476	      maxConcurrency: options.maxConcurrency ?? 2,
477	      pollIntervalMs: options.pollIntervalMs ?? 5000,
478	      heartbeatIntervalMs: options.heartbeatIntervalMs ?? 30_000,
479	      heartbeatTimeoutMs: options.heartbeatTimeoutMs ?? 90_000,
480	    };
481	  }
482	
483	  get size(): number { return this.workers.size; }
484	  get maxWorkers(): number { return this.options.maxWorkers; }
485	
486	  register(worker: WorkerInstance): void {
487	    if (this.workers.size >= this.options.maxWorkers) {
488	      throw new Error(`Worker pool full: max=${this.options.maxWorkers}`);
489	    }
490	    this.workers.set(worker.id, worker);
491	  }
492	
493	  unregister(workerId: string): void { this.workers.delete(workerId); }
494	  getWorker(workerId: string): WorkerInstance | undefined { return this.workers.get(workerId); }
495	  listWorkers(): WorkerInstance[] { return Array.from(this.workers.values()); }
496	
497	  setWorkerStatus(workerId: string, status: WorkerInstance["status"]): void {
498	    const worker = this.workers.get(workerId);
499	    if (worker) { worker.status = status; worker.lastHeartbeatAt = new Date(); }
500	  }
501	
502	  assignJob(workerId: string, job: JobRequest): void {
503	    const worker = this.workers.get(workerId);
504	    if (!worker) throw new Error(`Worker ${workerId} not found`);
505	    worker.status = "busy";
506	    worker.currentJob = job;
507	    worker.lastHeartbeatAt = new Date();
508	  }
509	
510	  releaseWorker(workerId: string, result: JobResult): void {
511	    const worker = this.workers.get(workerId);
512	    if (!worker) return;
513	    worker.status = "idle";
514	    worker.currentJob = null;
515	    worker.lastHeartbeatAt = new Date();
516	    if (result.status === "succeeded") worker.completedJobs++;
517	    else worker.failedJobs++;
518	  }
519	
520	  getIdleWorkers(): WorkerInstance[] { return this.listWorkers().filter(w => w.status === "idle"); }
521	  getBusyWorkers(): WorkerInstance[] { return this.listWorkers().filter(w => w.status === "busy"); }
522	
523	  checkStaleHeartbeats(): WorkerInstance[] {
524	    const now = Date.now();
525	    const stale: WorkerInstance[] = [];
526	    for (const worker of this.workers.values()) {
527	      if (now - worker.lastHeartbeatAt.getTime() > this.options.heartbeatTimeoutMs) {
528	        worker.status = "offline";
529	        stale.push(worker);
530	      }
531	    }
532	    return stale;
533	  }
534	
535	  getPoolStats() {
536	    const workers = this.listWorkers();
537	    return {
538	      total: workers.length,
539	      idle: workers.filter(w => w.status === "idle").length,
540	      busy: workers.filter(w => w.status === "busy").length,
541	      offline: workers.filter(w => w.status === "offline").length,
542	      maintenance: workers.filter(w => w.status === "maintenance").length,
543	      totalCompleted: workers.reduce((sum, w) => sum + w.completedJobs, 0),
544	      totalFailed: workers.reduce((sum, w) => sum + w.failedJobs, 0),
545	    };
546	  }
547	}
