560	  constructor(options: Partial<WorkerPoolOptions & WorkerEngineEvents> = {}) {
561	    this.pool = new WorkerPool({
562	      maxWorkers: options.maxWorkers ?? 4,
563	      maxConcurrency: options.maxConcurrency ?? 2,
