570	
571	  get isRunning(): boolean { return this.running; }
572	  get workerPool(): WorkerPool { return this.pool; }
573	
574	  registerWorker(config: WorkerConfig): WorkerInstance {
575	    const existing = this.pool.listWorkers().find(w => w.config.name === config.name);
576	    if (existing) return existing;
577	
578	    const instance: WorkerInstance = {
579	      id: `worker_${config.id}_${Date.now().toString(36)}`,
580	      name: config.name,
581	      config,
582	      status: "idle",
583	      currentJob: null,
584	      startedAt: new Date(),
585	      lastHeartbeatAt: new Date(),
586	      completedJobs: 0,
587	      failedJobs: 0,
588	    };
589	
590	    this.pool.register(instance);
591	    this.events.onWorkerRegistered?.(instance);
592	    return instance;
593	  }
594	
595	  deregisterWorker(workerId: string): void {
596	    const worker = this.pool.getWorker(workerId);
597	    if (worker) {
598	      this.pool.unregister(workerId);
599	      this.events.onWorkerDeregistered?.(workerId);
600	    }
601	  }
602	
603	  async submitJob(request: JobRequest): Promise<JobResult> {
604	    const worker = this.pool.getIdleWorkers()[0];
605	    if (!worker) throw new Error("No idle worker available");
606	
607	    this.events.onJobSubmitted?.(request);
608	    this.pool.assignJob(worker.id, request);
609	
610	    const ctx: WorkerContext = {
611	      workerId: worker.id,
612	      config: worker.config,
613	      safeTestMode: request.safeTestMode,
614	    };
615	
616	    const result = await executeJobInWorker(ctx, request);
617	    this.pool.releaseWorker(worker.id, result);
618	
619	    if (result.status === "succeeded") this.events.onJobCompleted?.(result);
620	    else this.events.onJobFailed?.(request, result.errorMessage ?? result.errorCode ?? "unknown");
621	
622	    return result;
623	  }
624	
625	  private async pollJobQueue(): Promise<void> {
626	    if (!this.running) return;
627	    try {
628	      const { listRuntimeJobs } = await import("../runtimeStore");
629	      const queuedJobs = listRuntimeJobs().filter(j => j.status === "queued" && j.queueName !== "bulk");
630	      const idleWorkers = this.pool.getIdleWorkers();
631	      if (idleWorkers.length === 0 || queuedJobs.length === 0) return;
632	
633	      const sortedJobs = queuedJobs.sort((a, b) => b.priority - a.priority);
634	      const dispatchCount = Math.min(idleWorkers.length, sortedJobs.length, 3);
635	
636	      for (let i = 0; i < dispatchCount; i++) {
637	        const job = sortedJobs[i];
638	        const worker = idleWorkers[i];
639	        const payload = job.payloadJson as Record<string, unknown>;
640	        const request: JobRequest = {
641	          jobPublicId: job.publicId,
642	          payload,
643	          proxyConfig: {},
644	          priority: job.priority,
645	          queueName: job.queueName,
646	          safeTestMode: false,
647	          maxRetries: job.maxAttempts,
648	        };
649	
650	        this.pool.assignJob(worker.id, request);
651	        this.events.onJobSubmitted?.(request);
652	        void this.executeJobDispatch(worker.id, request).catch(err => {
653	          console.error(`[WorkerEngine] Job dispatch error for ${request.jobPublicId}:`, err);
654	        });
655	      }
656	    } catch (err) { console.error("[WorkerEngine] pollJobQueue error:", err); }
657	  }
658	
659	  private async executeJobDispatch(workerId: string, request: JobRequest): Promise<JobResult> {
660	    try {
661	      const worker = this.pool.getWorker(workerId);
662	      const ctx: WorkerContext = {
663	        workerId,
664	        config: worker?.config ?? { id: 0, name: "unknown", concurrency: 1, safeTestMode: false, maxRetries: 3, proxyRotateAfterN: 20, ssnTimeoutMs: 90_000, browserTimeoutMs: 60_000 },
665	        safeTestMode: request.safeTestMode,
666	      };
667	      const result = await executeJobInWorker(ctx, request);
668	      this.pool.releaseWorker(workerId, result);
669	      if (result.status === "succeeded") this.events.onJobCompleted?.(result);
670	      else this.events.onJobFailed?.(request, result.errorMessage ?? "unknown");
671	      return result;
672	    } catch (err) {
673	      const errorMessage = err instanceof Error ? err.message : String(err);
674	      const failResult: JobResult = {
675	        jobPublicId: request.jobPublicId, status: "failed", creditScore: null,
676	        productScore: 1, dataQualityScore: 1, ssnProvided: false,
677	        extractedAt: new Date().toISOString(), executionMs: 0, proxyUsed: null,
678	        errorCode: "INTERNAL_ERROR", errorMessage,
679	      };
680	      this.pool.releaseWorker(workerId, failResult);
681	      this.events.onJobFailed?.(request, errorMessage);
682	      throw err;
683	    }
684	  }
685	
686	  private monitorHeartbeats(): void {
687	    for (const worker of this.pool.checkStaleHeartbeats()) {
688	      console.warn(`[WorkerEngine] Worker ${worker.name} heartbeat stale (last: ${worker.lastHeartbeatAt.toISOString()})`);
689	    }
690	  }
691	
692	  start(): void {
693	    if (this.running) return;
694	    this.running = true;
695	    console.info("[WorkerEngine] Starting worker engine...");
696	    this.pollTimer = setInterval(() => { void this.pollJobQueue(); }, this.options.pollIntervalMs);
697	    this.heartbeatTimer = setInterval(() => { this.monitorHeartbeats(); }, this.options.heartbeatIntervalMs);
698	    console.info(`[WorkerEngine] Engine started (poll=${this.options.pollIntervalMs}ms)`);
699	  }
700	
701	  async stop(): Promise<void> {
702	    if (!this.running) return;
703	    this.running = false;
704	    if (this.pollTimer) clearInterval(this.pollTimer);
705	    if (this.heartbeatTimer) clearInterval(this.heartbeatTimer);
706	    const busyWorkers = this.pool.getBusyWorkers();
707	    if (busyWorkers.length > 0) {
708	      console.info(`[WorkerEngine] Waiting for ${busyWorkers.length} busy workers...`);
709	      await new Promise<void>(resolve => setTimeout(resolve, 5000));
710	    }
711	    const proxyMod = await import("../_core/proxy").catch(() => null);
712	    if (proxyMod) await proxyMod.shutdown().catch(() => {});
713	    console.info("[WorkerEngine] Engine stopped");
714	  }
715	}
716	
717	// =============================================================================
718	// Internal: job execution inside a worker
719	// =============================================================================
720	
721	interface WorkerContext {
722	  workerId: string;
723	  config: WorkerConfig;
724	  safeTestMode: boolean;
725	}
726	
727	async function executeJobInWorker(ctx: WorkerContext, request: JobRequest): Promise<JobResult> {
728	  const startMs = Date.now();
729	
730	  if (request.safeTestMode || ctx.safeTestMode) {
731	    return {
732	      jobPublicId: request.jobPublicId, status: "succeeded",
733	      creditScore: 720, productScore: 15, dataQualityScore: 8,
734	      ssnProvided: false, extractedAt: new Date().toISOString(),
735	      executionMs: Date.now() - startMs, proxyUsed: "mock://safe-test",
736	      browserEvents: [
737	        { type: "safe_test_enter", timestamp: new Date().toISOString() },
738	        { type: "safe_test_complete", timestamp: new Date().toISOString() },
739	      ],
740	    };
741	  }
742	
743	  const fp = generateFingerprint();
744	  const ssnFlow = createSsnFlowRequest(request.jobPublicId);
745	  const ssnFromPayload = (request.payload.ssn ?? request.payload.socialSecurityNumber) as string | null;
746	  const activeFlow = ssnFromPayload ? provideSsnToFlow(ssnFlow, ssnFromPayload) : ssnFlow;
747	  const proxyUsed = request.proxyConfig?.providerHint ?? "evomi";
748	
749	  const simulateError = request.payload.simulateError as boolean | undefined;
750	  const simulateTimeout = request.payload.simulateTimeout as boolean | undefined;
751	
752	  if (simulateTimeout) {
753	    return {
754	      jobPublicId: request.jobPublicId, status: "timeout",
755	      creditScore: null, productScore: 1, dataQualityScore: 1,
756	      ssnProvided: activeFlow.ssn !== null, extractedAt: new Date().toISOString(),
757	      executionMs: Date.now() - startMs, proxyUsed,
758	      errorCode: "BROWSER_TIMEOUT", errorMessage: "Browser automation exceeded timeout threshold",
759	    };
760	  }
761	
762	  if (simulateError) {
763	    return {
764	      jobPublicId: request.jobPublicId, status: "failed",
765	      creditScore: null, productScore: 1, dataQualityScore: 1,
766	      ssnProvided: activeFlow.ssn !== null, extractedAt: new Date().toISOString(),
767	      executionMs: Date.now() - startMs, proxyUsed,
768	      errorCode: "EXECUTION_ERROR", errorMessage: "Job execution failed: " + (request.payload.errorDetail ?? "unknown"),
769	    };
770	  }
771	
772	  const scoreFromPayload = request.payload.creditScore ?? request.payload.rawCreditScore;
773	  const creditScore = typeof scoreFromPayload === "number" ? scoreFromPayload : null;
774	
775	  return {
776	    jobPublicId: request.jobPublicId, status: "succeeded",
777	    creditScore,
778	    productScore: creditScore ? Math.max(1, Math.min(20, Math.round((creditScore - 300) / 27.5))) : 1,
779	    dataQualityScore: creditScore ? 8 : 2,
780	    ssnProvided: activeFlow.ssn !== null, extractedAt: new Date().toISOString(),
781	    executionMs: Date.now() - startMs, proxyUsed,
782	    browserEvents: [
783	      { type: "fingerprint_generated", timestamp: new Date().toISOString(), detail: `UA: ${fp.userAgent.slice(0, 50)}...` },
784	      { type: "job_executed", timestamp: new Date().toISOString(), detail: `ssn=${activeFlow.ssn !== null ? "provided" : "not_required"} score=${creditScore}` },
785	    ],
786	  };
787	}
788	
789	// =============================================================================
790	// Module exports
791	// =============================================================================
