793	export { WorkerEngine, WorkerPool };
794	export type {
795	  WorkerConfig, WorkerInstance, JobRequest, JobResult,
796	  WorkerPoolOptions, WorkerEngineEvents, SsnFlowState,
797	  FingerprintProfile, Point, BezierCurve,
798	};
799	
800	export function createWorkerEngine(options?: Partial<WorkerPoolOptions & WorkerEngineEvents>): WorkerEngine {
801	  return new WorkerEngine(options);
802	}
