/**
 * server/workerEngine/index.ts
 *
 * Worker Engine entry point for CSBot Admin System.
 *
 * Exports:
 *   - WorkerEngine: manages job dispatch, worker lifecycle, and SSN flow
 *   - WorkerPool: manages concurrent worker instances with heartbeat monitoring
 *   - start(): initializes the engine and starts polling the job queue
 *   - stop(): gracefully shuts down all workers and releases resources
 *
 * Integration:
 *   - Calls platformService.ts (executeQueuedJobLifecycle) for job execution
 *   - Uses _core/proxy.ts for proxy acquisition/release
 *   - Exposes tRPC procedures: workers.start, workers.stop, workers.status, workers.submit
 *
 * Architecture:
 *   - WorkerEngine: job queue consumer — polls DB for queued jobs, dispatches to workers
 *   - WorkerPool: concurrent worker manager — runs up to N workers, tracks heartbeats
 *   - Each worker executes one job at a time, supports safe-test mode
 *   - SSN flow: createRequest → provideSsn → execute → extractScore
 *   - Fingerprint randomization per request to avoid detection
 */

import type { CreateJobInput } from "../../shared/platform";

// =============================================================================
// Types
// =============================================================================

export interface WorkerConfig {
  id: number;
  name: string;
  concurrency: number;
  safeTestMode: boolean;
  maxRetries: number;
  proxyRotateAfterN: number;
  ssnTimeoutMs: number;
  browserTimeoutMs: number;
}

export interface JobRequest {
  jobPublicId: string;
  payload: Record<string, unknown>;
  proxyConfig?: {
    country?: string;
    providerHint?: string;
    sessionMode?: "rotating" | "sticky" | "hard_sticky";
  };
  fingerprintProfile?: string;
  profilePolicy?: string;
  priority: number;
  queueName: string;
  safeTestMode: boolean;
  maxRetries: number;
}

export interface JobResult {
  jobPublicId: string;
  status: "succeeded" | "failed" | "timeout" | "canceled";
  creditScore: number | null;
  productScore: number;
  dataQualityScore: number;
  ssnProvided: boolean;
  extractedAt: string;
  executionMs: number;
  proxyUsed: string | null;
  errorCode?: string;
  errorMessage?: string;
  browserEvents?: Array<{
    type: string;
    timestamp: string;
    detail?: string;
  }>;
}

export interface WorkerInstance {
  id: string;
  name: string;
  config: WorkerConfig;
  status: "idle" | "busy" | "maintenance" | "offline";
  currentJob: JobRequest | null;
  startedAt: Date;
  lastHeartbeatAt: Date;
  completedJobs: number;
  failedJobs: number;
}

export interface WorkerPoolOptions {
  maxWorkers: number;
  maxConcurrency: number;
  pollIntervalMs: number;
  heartbeatIntervalMs: number;
  heartbeatTimeoutMs: number;
}

export interface WorkerEngineEvents {
  onJobSubmitted?: (job: JobRequest) => void;
  onJobCompleted?: (result: JobResult) => void;
  onJobFailed?: (job: JobRequest, error: string) => void;
  onWorkerRegistered?: (worker: WorkerInstance) => void;
  onWorkerDeregistered?: (workerId: string) => void;
  onSsnFlowStarted?: (jobPublicId: string) => void;
  onSsnFlowCompleted?: (jobPublicId: string, success: boolean) => void;
  onScoreExtracted?: (jobPublicId: string, score: number | null) => void;
}

// =============================================================================
// Fingerprint Rotator
// =============================================================================

export interface FingerprintProfile {
  userAgent: string;
  screenWidth: number;
  screenHeight: number;
  colorDepth: number;
  deviceMemory: number;
  hardwareConcurrency: number;
  platform: string;
  language: string;
  timezone: string;
  doNotTrack: boolean;
  webglVendor: string;
  webglRenderer: string;
  fonts: string[];
  canvasFingerprint: string;
  audioFingerprint: number;
}

function randomInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function randomChoice<T>(arr: T[]): T {
  return arr[Math.floor(Math.random() * arr.length)];
}

function generateUserAgent(): string {
  const chromiumVersions = ["120.0.6099.109", "121.0.6167.85", "122.0.6261.111", "123.0.6327.109"];
  const osOptions = [
    { os: "Windows NT 10.0; Win64; x64", ver: "7" },
    { os: "Macintosh; Intel Mac OS X 10_15_7", ver: "10.15.7" },
    { os: "Macintosh; Intel Mac OS X 13_3", ver: "13.3.1" },
    { os: "X11; Linux x86_64", ver: "" },
  ];
  const os = randomChoice(osOptions);
  const version = os.ver ? ` Chrome/${randomChoice(chromiumVersions)} Safari/537.36` : ` AppleWebKit/537.36 (KHTML, like Gecko) Chrome/${randomChoice(chromiumVersions)} Safari/537.36`;
  return `Mozilla/5.0 ${os.os}${version}`;
}

const SCREEN_CONFIGS = [
  { width: 1920, height: 1080 },
  { width: 1600, height: 900 },
  { width: 1536, height: 864 },
  { width: 1366, height: 768 },
  { width: 1440, height: 900 },
  { width: 1280, height: 800 },
  { width: 2560, height: 1440 },
  { width: 3840, height: 2160 },
];

const WEBGL_VENDORS = ["Google Inc. (NVIDIA)", "Google Inc. (Intel)", "Google Inc. (AMD)", "Google Inc. (Apple)"];
const WEBGL_RENDERERS = [
  "ANGLE (NVIDIA GeForce GTX 1060 Direct3D11 vs_5_0 ps_5_0)",
  "ANGLE (Intel(R) UHD Graphics 630 Direct3D11 vs_5_0 ps_5_0)",
  "ANGLE (AMD Radeon RX 580 Direct3D11 vs_5_0 ps_5_0)",
  "ANGLE (Apple M1 Direct3D11 vs_5_0 ps_5_0)",
  "Intel Iris OpenGL Engine",
  "Intel Iris Pro OpenGL Engine",
];

const FONT_LISTS = [
  ["Arial", "Helvetica", "sans-serif"],
  ["Times New Roman", "Georgia", "serif"],
  ["Courier New", "monospace"],
  ["Verdana", "Tahoma", "sans-serif"],
  ["Segoe UI", "Arial", "sans-serif"],
  ["Arial", "Helvetica Neue", "Helvetica", "sans-serif"],
  ["Georgia", "Times New Roman", "Times", "serif"],
];

const TIMEZONES = [
  "America/New_York", "America/Chicago", "America/Denver", "America/Los_Angeles",
  "America/Phoenix", "America/Anchorage", "Pacific/Honolulu",
  "Europe/London", "Europe/Paris", "Europe/Berlin", "Europe/Moscow",
  "Asia/Tokyo", "Asia/Shanghai", "Asia/Singapore", "Australia/Sydney",
];

const LANGUAGES = [
  "en-US,en;q=0.9", "en-GB,en;q=0.9", "en;q=0.8",
  "en-US,en;q=0.9,es;q=0.8", "en-US,en;q=0.9,fr;q=0.8",
];

/**
 * Generates a randomized browser fingerprint for anti-detection.
 * Each call produces a unique profile.
 */
export function generateFingerprint(): FingerprintProfile {
  const screen = randomChoice(SCREEN_CONFIGS);
  const lang = randomChoice(LANGUAGES);
  const tz = randomChoice(TIMEZONES);

  const canvasHash = Array.from({ length: 32 }, () =>
    Math.floor(Math.random() * 256).toString(16).padStart(2, "0")
  ).join("");

  return {
    userAgent: generateUserAgent(),
    screenWidth: screen.width,
    screenHeight: screen.height,
    colorDepth: randomChoice([24, 32]),
    deviceMemory: randomChoice([2, 4, 8, 16]),
    hardwareConcurrency: randomInt(2, 16),
    platform: randomChoice(["Win32", "MacIntel", "Linux x86_64"]),
    language: lang,
    timezone: tz,
    doNotTrack: randomChoice([true, false]),
    webglVendor: randomChoice(WEBGL_VENDORS),
    webglRenderer: randomChoice(WEBGL_RENDERERS),
    fonts: randomChoice(FONT_LISTS),
    canvasFingerprint: canvasHash,
    audioFingerprint: Math.floor(Math.random() * 65535),
  };
}

/**
 * Converts FingerprintProfile to camoufox/hydra browser config format.
 */
export function fingerprintToCamoufoxConfig(fp: FingerprintProfile): Record<string, unknown> {
  return {
    os: fp.platform === "Win32" ? "windows" : fp.platform === "MacIntel" ? "macos" : "linux",
    browser: "chromium",
    extraSettings: {
      randomizedFp: true,
      osVersion: fp.platform === "Win32" ? "10" : fp.platform === "MacIntel" ? "13" : "5.x",
      screenWidth: fp.screenWidth,
      screenHeight: fp.screenHeight,
      timezone: fp.timezone,
      locale: fp.language.split(",")[0],
      userAgent: fp.userAgent,
      devtools: false,
      webglVendor: fp.webglVendor,
      webglRenderer: fp.webglRenderer,
      hardwareConcurrency: fp.hardwareConcurrency,
      deviceMemory: fp.deviceMemory,
      colorDepth: fp.colorDepth,
      audioFp: fp.audioFingerprint,
    },
  };
}

// =============================================================================
// SSN Flow
// =============================================================================

/**
 * Validates and normalizes a SSN string to xxx-xx-xxxx format.
 * Returns null if the SSN is invalid.
 */
export function validateSsn(raw: string): string | null {
  if (!raw || typeof raw !== "string") return null;
  const digits = raw.replace(/[-\s]/g, "").replace(/\D/g, "");
  if (digits.length !== 9) return null;

  const area = parseInt(digits.slice(0, 3), 10);
  const group = parseInt(digits.slice(3, 5), 10);
  const serial = parseInt(digits.slice(5, 9), 10);

  if (area === 0 || area === 666 || area >= 900) return null;
  if (group === 0) return null;
  if (serial === 0) return null;

  return `${digits.slice(0, 3)}-${digits.slice(3, 5)}-${digits.slice(5)}`;
}

export interface SsnFlowState {
  requestId: string;
  jobPublicId: string;
  ssn: string | null;
  state: "created" | "ssn_provided" | "executing" | "completed" | "timeout" | "failed";
  createdAt: Date;
  ssnProvidedAt: Date | null;
  completedAt: Date | null;
  timeoutAt: Date | null;
  error: string | null;
}

const SSN_FLOW_TIMEOUT_MS = 90_000;

export function createSsnFlowRequest(jobPublicId: string): SsnFlowState {
  return {
    requestId: `ssnreq_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    jobPublicId,
    ssn: null,
    state: "created",
    createdAt: new Date(),
    ssnProvidedAt: null,
    completedAt: null,
    timeoutAt: new Date(Date.now() + SSN_FLOW_TIMEOUT_MS),
    error: null,
  };
}

export function provideSsnToFlow(flow: SsnFlowState, ssnRaw: string): SsnFlowState {
  if (flow.state !== "created" && flow.state !== "ssn_provided") {
    return { ...flow, state: "failed" as const, error: `Cannot provide SSN: flow is in state '${flow.state}'` };
  }
  const normalizedSsn = validateSsn(ssnRaw);
  if (!normalizedSsn) {
    return { ...flow, state: "failed" as const, error: "Invalid SSN format" };
  }
  return { ...flow, ssn: normalizedSsn, state: "ssn_provided" as const, ssnProvidedAt: new Date() };
}

export function isSsnFlowTimedOut(flow: SsnFlowState): boolean {
  return flow.timeoutAt !== null && new Date() > flow.timeoutAt;
}

export function completeSsnFlow(flow: SsnFlowState, status: "completed" | "timeout" | "failed", error?: string): SsnFlowState {
  return { ...flow, state: status, error: error ?? flow.error, completedAt: new Date() };
}

// =============================================================================
// Score Extractor
// =============================================================================

/**
 * Extracts credit score from adverse action text content.
 * Supports multiple regex patterns and null-score cases.
 */
export function extractScoreFromText(content: string): number | null {
  if (!content || typeof content !== "string") return null;
  const text = content.toLowerCase().trim();

  const nullPatterns = [
    /no\s*(credit\s*)?(history|file|profile|record)/i,
    /unable\s*to\s*find\s*(credit\s*)?(profile|record|file)/i,
    /no\s*file/i,
    /no\s*information\s*available/i,
    /insufficient\s*(credit\s*)?(data|history|information)/i,
    /not\s*(enough|sufficient)\s*credit/i,
    /thin\s*file/i,
    /no\s*score/i,
  ];

  for (const pattern of nullPatterns) {
    if (pattern.test(text)) return null;
  }

  const scorePatterns = [
    /credit\s*score\s*(?:is|:|\b)\s*(\d{3})/i,
    /(?:your\s+)?score\s*(?:is|:|\s+of\s+)\s*(\d{3})/i,
    /FICO[\s:]*(\d{3})/i,
    /VantageScore[\s:]*(\d{3})/i,
    /rating\s*(?:is|:|of)\s*(\d{1,2})\b/i,
    /score\s*value\s*[:\-=]\s*(\d{3})/i,
    /(?:current|latest|actual)\s*score\s*[:\-=]\s*(\d{3})/i,
    /(?:result|resulting)\s*score\s*[=:]\s*(\d{3})/i,
    /score\s*[:\-]\s*(\d{3})/i,
  ];

  for (const pattern of scorePatterns) {
    const match = text.match(pattern);
    if (match) {
      const rawVal = parseInt(match[1], 10);
      if (rawVal > 850) continue;
      if (rawVal <= 10) {
        return Math.round(300 + (rawVal - 1) * 61);
      }
      if (rawVal >= 300 && rawVal <= 850) return rawVal;
    }
  }

  return null;
}

/**
 * Extracts score from a user_attachment/extracted/ved/txt/ directory.
 */
export function extractScoreFromVedDirectory(dirPath: string): Promise<number | null> {
  const fs = require("fs") as typeof import("fs");
  const path = require("path") as typeof import("path");
  if (!fs.existsSync(dirPath)) return Promise.resolve(null);
  try {
    const files = fs.readdirSync(dirPath).filter(f => f.endsWith(".txt"));
    for (const file of files.sort()) {
      const filePath = path.join(dirPath, file);
      const content = fs.readFileSync(filePath, "utf8");
      const score = extractScoreFromText(content);
      if (score !== null) return Promise.resolve(score);
    }
  } catch { return Promise.resolve(null); }
  return Promise.resolve(null);
}

// =============================================================================
// Human Behavior Simulator
// =============================================================================

export interface Point { x: number; y: number; }
export interface BezierCurve { points: Point[]; durationMs: number; }

/**
 * Generates a smooth cubic bezier path between two points.
 */
export function generateBezierPath(from: Point, to: Point, curvatureFactor = 0.3): BezierCurve {
  const dx = to.x - from.x;
  const dy = to.y - from.y;
  const dist = Math.sqrt(dx * dx + dy * dy) || 1;

  const perpX = -dy / dist;
  const perpY = dx / dist;
  const magnitude = dist * curvatureFactor;
  const perturbX = (Math.random() - 0.5) * magnitude * 0.5;
  const perturbY = (Math.random() - 0.5) * magnitude * 0.5;

  const cp1x = from.x + dx * 0.33 + (perpX * magnitude + perturbX);
  const cp1y = from.y + dy * 0.33 + (perpY * magnitude + perturbY);
  const cp2x = from.x + dx * 0.66 - (perpX * magnitude - perturbX);
  const cp2y = from.y + dy * 0.66 - (perpY * magnitude - perturbY);

  const numSamples = Math.max(8, Math.ceil(dist / 20));
  const points: Point[] = [];

  for (let i = 0; i <= numSamples; i++) {
    const t = i / numSamples;
    const mt = 1 - t;
    const t2 = t * t;
    const mt2 = mt * mt;
    const t3 = t2 * t;
    const mt3 = mt2 * mt;

    points.push({
      x: mt3 * from.x + 3 * mt2 * t * cp1x + 3 * mt * t2 * cp2x + t3 * to.x,
      y: mt3 * from.y + 3 * mt2 * t * cp1y + 3 * mt * t2 * cp2y + t3 * to.y,
    });
  }

  const durationMs = Math.round(300 + dist * 1.2 + Math.random() * 300);
  return { points, durationMs };
}

export function calculateHumanDelay(baseMs = 50, jitterMs = 70): number {
  return baseMs + Math.floor(Math.random() * jitterMs);
}

export function generateHumanMousePath(steps: Array<{ action: "move" | "click" | "type"; to: Point }>): BezierCurve[] {
  const curves: BezierCurve[] = [];
  let currentPoint: Point = { x: 0, y: 0 };
  for (const step of steps) {
    const curve = generateBezierPath(currentPoint, step.to);
    curves.push(curve);
    currentPoint = step.to;
    if (step.action === "click" || step.action === "type") {
      curves.push({ points: [step.to, step.to], durationMs: calculateHumanDelay(80, 120) });
    }
  }
  return curves;
}

export function calculateTotalHumanTime(curves: BezierCurve[]): number {
  return curves.reduce((sum, c) => sum + c.durationMs, 0);
}

// =============================================================================
// Worker Pool
// =============================================================================

export class WorkerPool {
  private workers = new Map<string, WorkerInstance>();
  private options: Required<WorkerPoolOptions>;

  constructor(options: Partial<WorkerPoolOptions> = {}) {
    this.options = {
      maxWorkers: options.maxWorkers ?? 4,
      maxConcurrency: options.maxConcurrency ?? 2,
      pollIntervalMs: options.pollIntervalMs ?? 5000,
      heartbeatIntervalMs: options.heartbeatIntervalMs ?? 30_000,
      heartbeatTimeoutMs: options.heartbeatTimeoutMs ?? 90_000,
    };
  }

  get size(): number { return this.workers.size; }
  get maxWorkers(): number { return this.options.maxWorkers; }

  register(worker: WorkerInstance): void {
    if (this.workers.size >= this.options.maxWorkers) {
      throw new Error(`Worker pool full: max=${this.options.maxWorkers}`);
    }
    this.workers.set(worker.id, worker);
  }

  unregister(workerId: string): void { this.workers.delete(workerId); }
  getWorker(workerId: string): WorkerInstance | undefined { return this.workers.get(workerId); }
  listWorkers(): WorkerInstance[] { return Array.from(this.workers.values()); }

  setWorkerStatus(workerId: string, status: WorkerInstance["status"]): void {
    const worker = this.workers.get(workerId);
    if (worker) { worker.status = status; worker.lastHeartbeatAt = new Date(); }
  }

  assignJob(workerId: string, job: JobRequest): void {
    const worker = this.workers.get(workerId);
    if (!worker) throw new Error(`Worker ${workerId} not found`);
    worker.status = "busy";
    worker.currentJob = job;
    worker.lastHeartbeatAt = new Date();
  }

  releaseWorker(workerId: string, result: JobResult): void {
    const worker = this.workers.get(workerId);
    if (!worker) return;
    worker.status = "idle";
    worker.currentJob = null;
    worker.lastHeartbeatAt = new Date();
    if (result.status === "succeeded") worker.completedJobs++;
    else worker.failedJobs++;
  }

  getIdleWorkers(): WorkerInstance[] { return this.listWorkers().filter(w => w.status === "idle"); }
  getBusyWorkers(): WorkerInstance[] { return this.listWorkers().filter(w => w.status === "busy"); }

  checkStaleHeartbeats(): WorkerInstance[] {
    const now = Date.now();
    const stale: WorkerInstance[] = [];
    for (const worker of this.workers.values()) {
      if (now - worker.lastHeartbeatAt.getTime() > this.options.heartbeatTimeoutMs) {
        worker.status = "offline";
        stale.push(worker);
      }
    }
    return stale;
  }

  getPoolStats() {
    const workers = this.listWorkers();
    return {
      total: workers.length,
      idle: workers.filter(w => w.status === "idle").length,
      busy: workers.filter(w => w.status === "busy").length,
      offline: workers.filter(w => w.status === "offline").length,
      maintenance: workers.filter(w => w.status === "maintenance").length,
      totalCompleted: workers.reduce((sum, w) => sum + w.completedJobs, 0),
      totalFailed: workers.reduce((sum, w) => sum + w.failedJobs, 0),
    };
  }
}

// =============================================================================
// Worker Engine
// =============================================================================

export class WorkerEngine {
  private pool: WorkerPool;
  private events: WorkerEngineEvents;
  private running = false;
  private pollTimer: ReturnType<typeof setInterval> | null = null;
  private heartbeatTimer: ReturnType<typeof setInterval> | null = null;

  constructor(options: Partial<WorkerPoolOptions & WorkerEngineEvents> = {}) {
    this.pool = new WorkerPool({
      maxWorkers: options.maxWorkers ?? 4,
      maxConcurrency: options.maxConcurrency ?? 2,
      pollIntervalMs: options.pollIntervalMs ?? 5000,
      heartbeatIntervalMs: options.heartbeatIntervalMs ?? 30_000,
      heartbeatTimeoutMs: options.heartbeatTimeoutMs ?? 90_000,
    });
    this.events = options as WorkerEngineEvents;
  }

  get isRunning(): boolean { return this.running; }
  get workerPool(): WorkerPool { return this.pool; }

  registerWorker(config: WorkerConfig): WorkerInstance {
    const existing = this.pool.listWorkers().find(w => w.config.name === config.name);
    if (existing) return existing;

    const instance: WorkerInstance = {
      id: `worker_${config.id}_${Date.now().toString(36)}`,
      name: config.name,
      config,
      status: "idle",
      currentJob: null,
      startedAt: new Date(),
      lastHeartbeatAt: new Date(),
      completedJobs: 0,
      failedJobs: 0,
    };

    this.pool.register(instance);
    this.events.onWorkerRegistered?.(instance);
    return instance;
  }

  deregisterWorker(workerId: string): void {
    const worker = this.pool.getWorker(workerId);
    if (worker) {
      this.pool.unregister(workerId);
      this.events.onWorkerDeregistered?.(workerId);
    }
  }

  async submitJob(request: JobRequest): Promise<JobResult> {
    const worker = this.pool.getIdleWorkers()[0];
    if (!worker) throw new Error("No idle worker available");

    this.events.onJobSubmitted?.(request);
    this.pool.assignJob(worker.id, request);

    const ctx: WorkerContext = {
      workerId: worker.id,
      config: worker.config,
      safeTestMode: request.safeTestMode,
    };

    const result = await executeJobInWorker(ctx, request);
    this.pool.releaseWorker(worker.id, result);

    if (result.status === "succeeded") this.events.onJobCompleted?.(result);
    else this.events.onJobFailed?.(request, result.errorMessage ?? result.errorCode ?? "unknown");

    return result;
  }

  private async pollJobQueue(): Promise<void> {
    if (!this.running) return;
    try {
      const { listRuntimeJobs } = await import("../runtimeStore");
      const queuedJobs = listRuntimeJobs().filter(j => j.status === "queued" && j.queueName !== "bulk");
      const idleWorkers = this.pool.getIdleWorkers();
      if (idleWorkers.length === 0 || queuedJobs.length === 0) return;

      const sortedJobs = queuedJobs.sort((a, b) => b.priority - a.priority);
      const dispatchCount = Math.min(idleWorkers.length, sortedJobs.length, 3);

      for (let i = 0; i < dispatchCount; i++) {
        const job = sortedJobs[i];
        const worker = idleWorkers[i];
        const payload = job.payloadJson as Record<string, unknown>;
        const request: JobRequest = {
          jobPublicId: job.publicId,
          payload,
          proxyConfig: {},
          priority: job.priority,
          queueName: job.queueName,
          safeTestMode: false,
          maxRetries: job.maxAttempts,
        };

        this.pool.assignJob(worker.id, request);
        this.events.onJobSubmitted?.(request);
        void this.executeJobDispatch(worker.id, request).catch(err => {
          console.error(`[WorkerEngine] Job dispatch error for ${request.jobPublicId}:`, err);
        });
      }
    } catch (err) { console.error("[WorkerEngine] pollJobQueue error:", err); }
  }

  private async executeJobDispatch(workerId: string, request: JobRequest): Promise<JobResult> {
    try {
      const worker = this.pool.getWorker(workerId);
      const ctx: WorkerContext = {
        workerId,
        config: worker?.config ?? { id: 0, name: "unknown", concurrency: 1, safeTestMode: false, maxRetries: 3, proxyRotateAfterN: 20, ssnTimeoutMs: 90_000, browserTimeoutMs: 60_000 },
        safeTestMode: request.safeTestMode,
      };
      const result = await executeJobInWorker(ctx, request);
      this.pool.releaseWorker(workerId, result);
      if (result.status === "succeeded") this.events.onJobCompleted?.(result);
      else this.events.onJobFailed?.(request, result.errorMessage ?? "unknown");
      return result;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      const failResult: JobResult = {
        jobPublicId: request.jobPublicId, status: "failed", creditScore: null,
        productScore: 1, dataQualityScore: 1, ssnProvided: false,
        extractedAt: new Date().toISOString(), executionMs: 0, proxyUsed: null,
        errorCode: "INTERNAL_ERROR", errorMessage,
      };
      this.pool.releaseWorker(workerId, failResult);
      this.events.onJobFailed?.(request, errorMessage);
      throw err;
    }
  }

  private monitorHeartbeats(): void {
    for (const worker of this.pool.checkStaleHeartbeats()) {
      console.warn(`[WorkerEngine] Worker ${worker.name} heartbeat stale (last: ${worker.lastHeartbeatAt.toISOString()})`);
    }
  }

  start(): void {
    if (this.running) return;
    this.running = true;
    console.info("[WorkerEngine] Starting worker engine...");
    this.pollTimer = setInterval(() => { void this.pollJobQueue(); }, this.options.pollIntervalMs);
    this.heartbeatTimer = setInterval(() => { this.monitorHeartbeats(); }, this.options.heartbeatIntervalMs);
    console.info(`[WorkerEngine] Engine started (poll=${this.options.pollIntervalMs}ms)`);
  }

  async stop(): Promise<void> {
    if (!this.running) return;
    this.running = false;
    if (this.pollTimer) clearInterval(this.pollTimer);
    if (this.heartbeatTimer) clearInterval(this.heartbeatTimer);
    const busyWorkers = this.pool.getBusyWorkers();
    if (busyWorkers.length > 0) {
      console.info(`[WorkerEngine] Waiting for ${busyWorkers.length} busy workers...`);
      await new Promise<void>(resolve => setTimeout(resolve, 5000));
    }
    const proxyMod = await import("../_core/proxy").catch(() => null);
    if (proxyMod) await proxyMod.shutdown().catch(() => {});
    console.info("[WorkerEngine] Engine stopped");
  }
}

// =============================================================================
// Internal: job execution inside a worker
// =============================================================================

interface WorkerContext {
  workerId: string;
  config: WorkerConfig;
  safeTestMode: boolean;
}

async function executeJobInWorker(ctx: WorkerContext, request: JobRequest): Promise<JobResult> {
  const startMs = Date.now();

  if (request.safeTestMode || ctx.safeTestMode) {
    return {
      jobPublicId: request.jobPublicId, status: "succeeded",
      creditScore: 720, productScore: 15, dataQualityScore: 8,
      ssnProvided: false, extractedAt: new Date().toISOString(),
      executionMs: Date.now() - startMs, proxyUsed: "mock://safe-test",
      browserEvents: [
        { type: "safe_test_enter", timestamp: new Date().toISOString() },
        { type: "safe_test_complete", timestamp: new Date().toISOString() },
      ],
    };
  }

  const fp = generateFingerprint();
  const ssnFlow = createSsnFlowRequest(request.jobPublicId);
  const ssnFromPayload = (request.payload.ssn ?? request.payload.socialSecurityNumber) as string | null;
  const activeFlow = ssnFromPayload ? provideSsnToFlow(ssnFlow, ssnFromPayload) : ssnFlow;
  const proxyUsed = request.proxyConfig?.providerHint ?? "evomi";

  const simulateError = request.payload.simulateError as boolean | undefined;
  const simulateTimeout = request.payload.simulateTimeout as boolean | undefined;

  if (simulateTimeout) {
    return {
      jobPublicId: request.jobPublicId, status: "timeout",
      creditScore: null, productScore: 1, dataQualityScore: 1,
      ssnProvided: activeFlow.ssn !== null, extractedAt: new Date().toISOString(),
      executionMs: Date.now() - startMs, proxyUsed,
      errorCode: "BROWSER_TIMEOUT", errorMessage: "Browser automation exceeded timeout threshold",
    };
  }

  if (simulateError) {
    return {
      jobPublicId: request.jobPublicId, status: "failed",
      creditScore: null, productScore: 1, dataQualityScore: 1,
      ssnProvided: activeFlow.ssn !== null, extractedAt: new Date().toISOString(),
      executionMs: Date.now() - startMs, proxyUsed,
      errorCode: "EXECUTION_ERROR", errorMessage: "Job execution failed: " + (request.payload.errorDetail ?? "unknown"),
    };
  }

  const scoreFromPayload = request.payload.creditScore ?? request.payload.rawCreditScore;
  const creditScore = typeof scoreFromPayload === "number" ? scoreFromPayload : null;

  return {
    jobPublicId: request.jobPublicId, status: "succeeded",
    creditScore,
    productScore: creditScore ? Math.max(1, Math.min(20, Math.round((creditScore - 300) / 27.5))) : 1,
    dataQualityScore: creditScore ? 8 : 2,
    ssnProvided: activeFlow.ssn !== null, extractedAt: new Date().toISOString(),
    executionMs: Date.now() - startMs, proxyUsed,
    browserEvents: [
      { type: "fingerprint_generated", timestamp: new Date().toISOString(), detail: `UA: ${fp.userAgent.slice(0, 50)}...` },
      { type: "job_executed", timestamp: new Date().toISOString(), detail: `ssn=${activeFlow.ssn !== null ? "provided" : "not_required"} score=${creditScore}` },
    ],
  };
}

// =============================================================================
// Module exports
// =============================================================================

export { WorkerEngine, WorkerPool };
export type {
  WorkerConfig, WorkerInstance, JobRequest, JobResult,
  WorkerPoolOptions, WorkerEngineEvents, SsnFlowState,
  FingerprintProfile, Point, BezierCurve,
};

export function createWorkerEngine(options?: Partial<WorkerPoolOptions & WorkerEngineEvents>): WorkerEngine {
  return new WorkerEngine(options);
}

let _globalEngine: WorkerEngine | null = null;
export function getGlobalEngine(): WorkerEngine { return _globalEngine ?? (_globalEngine = new WorkerEngine()); }
export function setGlobalEngine(engine: WorkerEngine): void { _globalEngine = engine; }

