59	export interface JobResult {
60	  jobId: string;
61	  status: JobStatus;
62	  creditScore: number | null;
63	  productScore: number | null;
64	  dataQualityScore: number | null;
65	  status_: "success" | "review" | "decline" | "no_file" | "error" | null;
66	  error: string | null;
67	  workerId: number | null;
68	  proxyIp: string | null;
69	  durationMs: number | null;
70	  needsSsn: boolean;
71	  source: "safe_test" | "browser" | "api" | "dashboard" | "telegram" | "import" | "system" | "testbench";
72	  explanations?: string[];
73	  proxyLeaseId?: string;
74	}
