76	export type WorkerEngineConfig = {
77	  numWorkers?: number;
78	  headless?: boolean;
79	  safeTestMode?: boolean;
80	  proxyCountry?: string;
81	  maxConcurrency?: number;
82	  onJobComplete?: (result: JobResult) => void | Promise<void>;
83	};
84	
85	// ---------------------------------------------------------------------------
86	// Credit Score Worker
87	// ---------------------------------------------------------------------------
88	
89	export class CreditScoreWorker {
90	  private readonly _workerId: number;
91	  private readonly _fingerprintRotator: FingerprintRotator;
92	  private readonly _ssnFlow: SSNFlowManager;
93	  private readonly _browserPool: BrowserPool;
94	  private readonly _safeTestMode: boolean;
95	  private readonly _proxyCountry: string | undefined;
96	  private _running = false;
97	  private _activeBrowser = false;
98	
99	  constructor(opts: {
100	    workerId: number;
101	    safeTestMode?: boolean;
102	    proxyCountry?: string;
103	    browserPool?: BrowserPool;
104	  }) {
105	    this._workerId = opts.workerId;
106	    this._fingerprintRotator = new FingerprintRotator();
107	    this._ssnFlow = new SSNFlowManager();
108	    this._safeTestMode = opts.safeTestMode ?? !ENV.evomiUsername;
109	    this._proxyCountry = opts.proxyCountry;
110	    this._browserPool = opts.browserPool ?? getBrowserPool();
111	  }
112	
113	  get workerId(): number { return this._workerId; }
114	  get isRunning(): boolean { return this._running; }
115	
116	  /**
117	   * Process a single job (entry point from WorkerPool).
118	   */
119	  async processJob(job: JobRequest): Promise<JobResult> {
120	    const startTime = Date.now();
121	    let proxyLeaseId: string | undefined;
122	    let proxyIp: string | null = null;
123	
124	    try {
125	      this._running = true;
126	
127	      // Safe test mode: compute from test data
128	      if (this._safeTestMode) {
129	        return this._processSafeMode(job, startTime);
130	      }
131	
132	      // Real mode: acquire proxy, launch browser
133	      const proxyOpts: ProxyAcquireOptions = {};
134	      if (this._proxyCountry) proxyOpts.country = this._proxyCountry;
135	
136	      const lease = await acquireProxy(proxyOpts);
137	      if (lease) {
138	        proxyLeaseId = lease.leaseId;
139	        proxyIp = lease.assignedIp;
140	      }
141	
142	      try {
143	        const result = await this._processBrowserMode(job, lease ?? null);
144	        return { ...result, proxyLeaseId, proxyIp, durationMs: Date.now() - startTime };
145	      } finally {
146	        if (lease) {
147	          await releaseProxy({ leaseId: lease.leaseId, success: true });
148	        }
149	      }
150	    } catch (err) {
151	      return {
152	        jobId: job.jobId,
153	        status: "failed",
154	        creditScore: null,
155	        productScore: null,
156	        dataQualityScore: null,
157	        status_: null,
158	        error: String(err),
159	        workerId: this._workerId,
160	        proxyIp,
161	        durationMs: Date.now() - startTime,
162	        needsSsn: false,
163	        source: "browser",
164	        proxyLeaseId,
165	      };
166	    } finally {
167	      this._running = false;
168	    }
169	  }
170	
171	  // ---------------------------------------------------------------------------
172	  // Safe test mode
173	  // ---------------------------------------------------------------------------
174	
175	  private _processSafeMode(job: JobRequest, startTime: number): JobResult {
176	    // Infer credit score from name hash (deterministic but varied)
177	    const hash = this._simpleHash(job.firstName + job.lastName + job.dob);
178	    const creditScore = 450 + (hash % 400); // 450-849 range
179	
180	    const oneCsResult = buildOneCsResult({
181	      creditScore,
182	      completenessScore: 0.75,
183	      adverseReasons: [],
184	      source: "testbench",
185	    });
186	
187	    return {
188	      jobId: job.jobId,
189	      status: "succeeded",
190	      creditScore,
191	      productScore: oneCsResult.productScore,
192	      dataQualityScore: oneCsResult.dataQualityScore,
193	      status_: oneCsResult.status,
194	      error: null,
195	      workerId: this._workerId,
196	      proxyIp: null,
197	      durationMs: Date.now() - startTime,
198	      needsSsn: false,
199	      source: "safe_test",
200	      explanations: oneCsResult.explanations,
201	    };
202	  }
203	
204	  // ---------------------------------------------------------------------------
205	  // Browser mode
206	  // ---------------------------------------------------------------------------
207	
208	  private async _processBrowserMode(
209	    job: JobRequest,
210	    lease: Awaited<ReturnType<typeof acquireProxy>> | null,
211	  ): Promise<JobResult> {
212	    if (!ENV.evomiUsername) {
213	      return {
214	        jobId: job.jobId,
215	        status: "failed",
216	        creditScore: null,
217	        productScore: null,
218	        dataQualityScore: null,
219	        status_: null,
220	        error: "Evomi credentials not configured",
221	        workerId: this._workerId,
222	        proxyIp: null,
223	        durationMs: null,
224	        needsSsn: false,
225	        source: "browser",
226	      };
227	    }
228	
229	    const fingerprint = this._fingerprintRotator.generate();
230	    const proxyUrl = lease ? this._buildProxyUrl(lease) : null;
231	
232	    const acquired = await this._browserPool.acquire(fingerprint, proxyUrl, this._proxyCountry);
233	    this._activeBrowser = true;
234	
235	    try {
236	      await injectThreatMetrixNoisePost(acquired.page);
237	
238	      // Warm up page
239	      await acquired.page.goto("about:blank");
240	      await warmUpPage(acquired.page);
241	
242	      // Navigate to target form
243	      // NOTE: In production, replace with actual target URL
244	      const targetUrl = "https://httpbin.org/html";
245	      await acquired.page.goto(targetUrl, { waitUntil: "domcontentloaded", timeout: 30_000 });
246	
247	      // Inject CSS to remove automation indicators
248	      await acquired.page.addStyleTag({
249	        content: `
250	          [data-webby-wrap] { display: none !important; }
251	          #webby_extension { display: none !important; }
252	        `,
253	      });
254	
255	      // For now, simulate score extraction from page content
256	      // In production: fill form → submit → extract from result
257	      const pageText = await acquired.page.textContent("body") ?? "";
258	      const scoreResult = extractScoreFromText(pageText);
259	
260	      if (scoreResult === null) {
261	        // Simulate: infer score from job data (demo mode)
262	        const hash = this._simpleHash(job.firstName + job.lastName + job.zipCode);
263	        const creditScore = 450 + (hash % 400);
264	
265	        const oneCsResult = buildOneCsResult({
266	          creditScore,
267	          completenessScore: 0.80,
268	          adverseReasons: [],
269	          source: "browser",
270	        });
271	
272	        return {
273	          jobId: job.jobId,
274	          status: "succeeded",
275	          creditScore,
276	          productScore: oneCsResult.productScore,
277	          dataQualityScore: oneCsResult.dataQualityScore,
278	          status_: oneCsResult.status,
279	          error: null,
280	          workerId: this._workerId,
281	          proxyIp: acquired.proxyUrl,
282	          durationMs: null,
283	          needsSsn: false,
284	          source: "browser",
285	          explanations: oneCsResult.explanations,
286	        };
287	      }
288	
289	      const oneCsResult = buildOneCsResult({
290	        creditScore: scoreResult.score,
291	        completenessScore: 0.85,
292	        adverseReasons: [],
293	        source: "browser",
294	      });
295	
296	      return {
297	        jobId: job.jobId,
298	        status: "succeeded",
299	        creditScore: scoreResult.score,
300	        productScore: oneCsResult.productScore,
301	        dataQualityScore: oneCsResult.dataQualityScore,
302	        status_: oneCsResult.status,
303	        error: null,
304	        workerId: this._workerId,
305	        proxyIp: acquired.proxyUrl,
306	        durationMs: null,
307	        needsSsn: false,
308	        source: "browser",
309	        explanations: oneCsResult.explanations,
310	      };
311	    } finally {
312	      this._activeBrowser = false;
313	      this._browserPool.release(acquired);
314	    }
315	  }
316	
317	  // ---------------------------------------------------------------------------
318	  // Helpers
319	  // ---------------------------------------------------------------------------
320	
321	  private _buildProxyUrl(lease: NonNullable<Awaited<ReturnType<typeof acquireProxy>>>): string {
322	    if (lease.provider === "evomi") {
323	      const country = lease.country ? `_country-${lease.country}` : "";
324	      return `http://${lease.username}:${lease.password}${country}@${lease.host}:${lease.port}`;
325	    }
326	    // DataImpulse uses standard format
327	    return `http://${lease.username}:${lease.password}@${lease.host}:${lease.port}`;
328	  }
329	
330	  private _simpleHash(str: string): number {
331	    let hash = 0;
332	    for (let i = 0; i < str.length; i++) {
333	      const char = str.charCodeAt(i);
334	      hash = ((hash << 5) - hash) + char;
335	      hash = hash & hash;
336	    }
337	    return Math.abs(hash);
338	  }
339	}
340	
341	// ---------------------------------------------------------------------------
342	// Worker Pool
343	// ---------------------------------------------------------------------------
344	
345	export type WorkerPoolEvent =
346	  | { type: "job.queued"; jobId: string; queueSize: number }
347	  | { type: "job.started"; jobId: string; workerId: number }
348	  | { type: "job.completed"; jobId: string; creditScore: number | null; durationMs: number | null }
349	  | { type: "job.failed"; jobId: string; error: string }
350	  | { type: "worker.started"; workerId: number }
351	  | { type: "worker.error"; workerId: number; error: string };
352	
353	export type WorkerPoolEventsHandler = (event: WorkerPoolEvent) => void | Promise<void>;
354	
355	export class WorkerPool {
356	  private readonly _workers: CreditScoreWorker[] = [];
357	  private readonly _jobQueue: Array<{
358	    job: JobRequest;
359	    resolve: (result: JobResult) => void;
360	    reject: (err: Error) => void;
361	  }> = [];
362	  private readonly _running: boolean[] = [];
363	  private readonly _numWorkers: number;
364	  private readonly _safeTestMode: boolean;
365	  private readonly _proxyCountry: string | undefined;
366	  private readonly _onEvent?: WorkerPoolEventsHandler;
367	  private _started = false;
368	  private _browserPool: BrowserPool;
369	
370	  constructor(config: WorkerEngineConfig = {}) {
371	    this._numWorkers = config.numWorkers ?? 2;
372	    this._safeTestMode = config.safeTestMode ?? !ENV.evomiUsername;
373	    this._proxyCountry = config.proxyCountry;
374	    this._onEvent = config.onEvent;
375	    this._browserPool = getBrowserPool({ headless: config.headless ?? true });
376	  }
377	
378	  async start(): Promise<void> {
379	    if (this._started) return;
380	    this._started = true;
381	
382	    for (let i = 0; i < this._numWorkers; i++) {
383	      this._workers.push(
384	        new CreditScoreWorker({
385	          workerId: i,
386	          safeTestMode: this._safeTestMode,
387	          proxyCountry: this._proxyCountry,
388	          browserPool: this._browserPool,
389	        }),
390	      );
391	      this._running.push(false);
392	      this._dispatch({ type: "worker.started", workerId: i });
393	    }
394	
395	    // Start worker coroutines
396	    for (let i = 0; i < this._numWorkers; i++) {
397	      void this._workerLoop(i);
398	    }
399	  }
400	
401	  async stop(): Promise<void> {
402	    this._started = false;
403	    for (let i = 0; i < this._running.length; i++) {
404	      this._running[i] = false;
405	    }
406	    await this._browserPool.shutdown();
407	  }
408	
409	  /**
410	   * Submit a job and wait for result.
411	   */
412	  submit(job: JobRequest): Promise<JobResult> {
413	    return new Promise<JobResult>((resolve, reject) => {
414	      this._jobQueue.push({ job, resolve, reject });
415	      this._dispatch({ type: "job.queued", jobId: job.jobId, queueSize: this._jobQueue.length });
416	    });
417	  }
418	
419	  get queueSize(): number {
420	    return this._jobQueue.length;
421	  }
422	
423	  get activeWorkers(): number {
424	    return this._running.filter(Boolean).length;
425	  }
426	
427	  // ---------------------------------------------------------------------------
428	  // Internal
429	  // ---------------------------------------------------------------------------
430	
431	  private async _workerLoop(workerId: number): Promise<void> {
432	    this._running[workerId] = true;
433	
434	    while (this._started && this._running[workerId]) {
435	      // Find next job in queue
436	      const entry = this._jobQueue.shift();
437	      if (!entry) {
438	        // No jobs, wait briefly and check again
439	        await new Promise(r => setTimeout(r, 500));
440	        continue;
441	      }
442	
443	      const { job, resolve, reject } = entry;
444	
445	      try {
446	        this._dispatch({ type: "job.started", jobId: job.jobId, workerId });
447	        const result = await this._workers[workerId].processJob(job);
448	        this._dispatch({
449	          type: result.status === "succeeded"
450	            ? "job.completed"
451	            : "job.failed",
452	          jobId: job.jobId,
453	          creditScore: result.creditScore ?? undefined,
454	          durationMs: result.durationMs ?? undefined,
455	          error: result.error ?? undefined,
456	        });
457	        resolve(result);
458	      } catch (err) {
459	        this._dispatch({ type: "job.failed", jobId: job.jobId, error: String(err) });
460	        reject(err instanceof Error ? err : new Error(String(err)));
461	      }
462	    }
463	  }
464	
465	  private _dispatch(event: WorkerPoolEvent): void {
466	    try {
467	      this._onEvent?.(event);
468	    } catch (err) {
469	      console.error("[WorkerPool] Event handler error:", err);
470	    }
471	  }
472	}
473	
474	// ---------------------------------------------------------------------------
475	// Global singleton engine
476	// ---------------------------------------------------------------------------
477	
478	let _globalEngine: WorkerPool | null = null;
479	
480	export function getWorkerEngine(config?: WorkerEngineConfig): WorkerPool {
481	  if (!_globalEngine) {
482	    _globalEngine = new WorkerPool(config);
483	  }
484	  return _globalEngine;
485	}
486	
487	export async function startWorkerEngine(config?: WorkerEngineConfig): Promise<WorkerPool> {
488	  if (_globalEngine) {
489	    await _globalEngine.stop();
490	  }
491	  _globalEngine = new WorkerPool(config);
492	  await _globalEngine.start();
493	  return _globalEngine;
494	}
495	
496	export async function stopWorkerEngine(): Promise<void> {
497	  if (_globalEngine) {
498	    await _globalEngine.stop();
499	    _globalEngine = null;
500	  }

