import { describe, it, expect } from "vitest";
import {
  validateSsn,
  createSsnFlowRequest,
  provideSsnToFlow,
  isSsnFlowTimedOut,
  completeSsnFlow,
} from "./index";

describe("SSN Flow — validateSsn", () => {
  it('normalizeizes "123-45-6789" → "123-45-6789"', () => {
    expect(validateSsn("123-45-6789")).toBe("123-45-6789");
  });

  it('normalizes "123456789" → "123-45-6789"', () => {
    expect(validateSsn("123456789")).toBe("123-45-6789");
  });

  it('normalizes "123 45 6789" with spaces → "123-45-6789"', () => {
    expect(validateSsn("123 45 6789")).toBe("123-45-6789");
  });

  it('normalizes "  123-45-6789  " with whitespace → "123-45-6789"', () => {
    expect(validateSsn("  123-45-6789  ")).toBe("123-45-6789");
  });

  it("returns null for 10 digits (SSN with extra digit)", () => {
    expect(validateSsn("123-456-7890")).toBe(null);
  });

  it("returns null for 8 digits (too short)", () => {
    expect(validateSsn("12345678")).toBe(null);
  });

  it("returns null for 11 digits (with hyphens over-formatted)", () => {
    expect(validateSsn("123-456-78901")).toBe(null);
  });

  it("returns null for null / undefined", () => {
    // @ts-expect-error — testing runtime behavior
    expect(validateSsn(null)).toBe(null);
    // @ts-expect-error
    expect(validateSsn(undefined)).toBe(null);
  });

  it("returns null for empty string", () => {
    expect(validateSsn("")).toBe(null);
    expect(validateSsn("   ")).toBe(null);
  });

  it("returns null for non-numeric strings", () => {
    expect(validateSsn("abc-def-ghij")).toBe(null);
    expect(validateSsn("abcdefghij")).toBe(null);
  });

  it("returns null for area number 000", () => {
    expect(validateSsn("000-45-6789")).toBe(null);
  });

  it("returns null for area number 666", () => {
    expect(validateSsn("666-45-6789")).toBe(null);
  });

  it("returns null for area number 900-999", () => {
    expect(validateSsn("900-45-6789")).toBe(null);
    expect(validateSsn("999-45-6789")).toBe(null);
  });

  it("returns null for group 00", () => {
    expect(validateSsn("123-00-6789")).toBe(null);
  });

  it("returns null for serial 0000", () => {
    expect(validateSsn("123-45-0000")).toBe(null);
  });

  it("accepts valid SSN with minimum valid area 001", () => {
    expect(validateSsn("001-45-6789")).toBe("001-45-6789");
  });

  it("accepts valid SSN with max area 899", () => {
    expect(validateSsn("899-45-6789")).toBe("899-45-6789");
  });

  it("accepts valid SSN with group 01-99", () => {
    expect(validateSsn("123-01-6789")).toBe("123-01-6789");
    expect(validateSsn("123-99-6789")).toBe("123-99-6789");
  });

  it("accepts valid SSN with serial 0001-9999", () => {
    expect(validateSsn("123-45-0001")).toBe("123-45-0001");
    expect(validateSsn("123-45-9999")).toBe("123-45-9999");
  });

  it("strips existing hyphens then normalizes", () => {
    expect(validateSsn("123-45-6789")).toBe("123-45-6789");
    expect(validateSsn("123-456-789")).toBe("123-45-6789");
  });
});

describe("SSN Flow — createSsnFlowRequest", () => {
  it("creates flow with correct initial state", () => {
    const flow = createSsnFlowRequest("job_test_001");

    expect(flow.jobPublicId).toBe("job_test_001");
    expect(flow.ssn).toBeNull();
    expect(flow.state).toBe("created");
    expect(flow.requestId).toMatch(/^ssnreq_\d+_[a-z0-9]+$/);
    expect(flow.createdAt).toBeInstanceOf(Date);
    expect(flow.ssnProvidedAt).toBeNull();
    expect(flow.completedAt).toBeNull();
    expect(flow.timeoutAt).toBeInstanceOf(Date);
    expect(flow.error).toBeNull();
  });

  it("timeout is set to now + SSN_FLOW_TIMEOUT_MS (90s)", () => {
    const flow = createSsnFlowRequest("job_any");
    const now = Date.now();
    const expectedTimeout = now + 90_000;

    // Allow 100ms tolerance
    expect(Math.abs(flow.timeoutAt!.getTime() - expectedTimeout)).toBeLessThan(200);
  });

  it("each call generates a unique requestId", () => {
    const ids = new Set<string>();
    for (let i = 0; i < 50; i++) {
      ids.add(createSsnFlowRequest(`job_${i}`).requestId);
    }
    expect(ids.size).toBe(50);
  });
});

describe("SSN Flow — provideSsnToFlow", () => {
  it("provides valid SSN and transitions state to ssn_provided", () => {
    const flow = createSsnFlowRequest("job_ssn_001");
    const updated = provideSsnToFlow(flow, "123-45-6789");

    expect(updated.state).toBe("ssn_provided");
    expect(updated.ssn).toBe("123-45-6789");
    expect(updated.ssnProvidedAt).toBeInstanceOf(Date);
    expect(updated.error).toBeNull();
    // Original flow is not mutated
    expect(flow.state).toBe("created");
    expect(flow.ssn).toBeNull();
  });

  it("normalizes non-dashed SSN input", () => {
    const flow = createSsnFlowRequest("job_ssn_002");
    const updated = provideSsnToFlow(flow, "123456789");

    expect(updated.state).toBe("ssn_provided");
    expect(updated.ssn).toBe("123-45-6789");
  });

  it("rejects invalid SSN and transitions to failed state", () => {
    const flow = createSsnFlowRequest("job_ssn_003");
    const updated = provideSsnToFlow(flow, "000-00-0000");

    expect(updated.state).toBe("failed");
    expect(updated.ssn).toBeNull();
    expect(updated.error).toContain("Invalid SSN");
  });

  it("rejects SSN with 10 digits", () => {
    const flow = createSsnFlowRequest("job_ssn_004");
    const updated = provideSsnToFlow(flow, "123-456-7890");

    expect(updated.state).toBe("failed");
    expect(updated.error).toContain("Invalid SSN");
  });

  it("rejects SSN with wrong format (too short)", () => {
    const flow = createSsnFlowRequest("job_ssn_005");
    const updated = provideSsnToFlow(flow, "12345678");

    expect(updated.state).toBe("failed");
  });

  it("fails when flow is already completed", () => {
    const flow = completeSsnFlow(createSsnFlowRequest("job_done"), "completed");
    const updated = provideSsnToFlow(flow, "123-45-6789");

    expect(updated.state).toBe("failed");
    expect(updated.error).toContain("Cannot provide SSN");
    expect(updated.error).toContain("completed");
  });

  it("fails when flow is already timed out", () => {
    const flow = completeSsnFlow(createSsnFlowRequest("job_to"), "timeout");
    const updated = provideSsnToFlow(flow, "123-45-6789");

    expect(updated.state).toBe("failed");
    expect(updated.error).toContain("timeout");
  });

  it("fails when flow is already failed", () => {
    const flow = completeSsnFlow(createSsnFlowRequest("job_fail"), "failed", "Previous error");
    const updated = provideSsnToFlow(flow, "123-45-6789");

    expect(updated.state).toBe("failed");
    expect(updated.error).toContain("Previous error");
  });

  it("allows provideSsn on ssn_provided state (re-submit with new value)", () => {
    const flow = createSsnFlowRequest("job_resubmit");
    const first = provideSsnToFlow(flow, "123-45-6789");
    const second = provideSsnToFlow(first, "999-99-9999");

    expect(second.state).toBe("ssn_provided");
    expect(second.ssn).toBe("999-99-9999");
    expect(second.ssnProvidedAt).toBeInstanceOf(Date);
  });

  it("requestId is preserved across provideSsn calls", () => {
    const flow = createSsnFlowRequest("job_same_id");
    const first = provideSsnToFlow(flow, "123-45-6789");
    const second = provideSsnToFlow(first, "999-99-9999");

    expect(second.requestId).toBe(flow.requestId);
    expect(first.requestId).toBe(flow.requestId);
  });
});

describe("SSN Flow — isSsnFlowTimedOut", () => {
  it("returns false when timeout has not been reached", () => {
    const flow = createSsnFlowRequest("job_active");
    // flow.timeoutAt is 90s in the future
    expect(isSsnFlowTimedOut(flow)).toBe(false);
  });

  it("returns true when timeout has passed", () => {
    const flow = createSsnFlowRequest("job_old");
    // Manually set timeout to the past
    flow.timeoutAt = new Date(Date.now() - 1000);
    expect(isSsnFlowTimedOut(flow)).toBe(true);
  });

  it("returns false when timeoutAt is null", () => {
    const flow = createSsnFlowRequest("job_null_timeout");
    flow.timeoutAt = null;
    expect(isSsnFlowTimedOut(flow)).toBe(false);
  });
});

describe("SSN Flow — completeSsnFlow", () => {
  it("marks flow as completed with timestamp", () => {
    const flow = createSsnFlowRequest("job_complete");
    const completed = completeSsnFlow(flow, "completed");

    expect(completed.state).toBe("completed");
    expect(completed.completedAt).toBeInstanceOf(Date);
    expect(completed.error).toBeNull();
  });

  it("marks flow as timeout", () => {
    const flow = createSsnFlowRequest("job_timeout");
    const timedOut = completeSsnFlow(flow, "timeout");

    expect(timedOut.state).toBe("timeout");
    expect(timedOut.completedAt).toBeInstanceOf(Date);
  });

  it("marks flow as failed with error message", () => {
    const flow = createSsnFlowRequest("job_failed");
    const failed = completeSsnFlow(flow, "failed", "Network unreachable");

    expect(failed.state).toBe("failed");
    expect(failed.error).toBe("Network unreachable");
    expect(failed.completedAt).toBeInstanceOf(Date);
  });

  it("preserves error from flow if none provided to completeSsnFlow", () => {
    const flow = createSsnFlowRequest("job_err_preserved");
    flow.error = "Previous issue";
    const failed = completeSsnFlow(flow, "failed");

    expect(failed.error).toBe("Previous issue");
  });

  it("preserves requestId through completion", () => {
    const flow = createSsnFlowRequest("job_reqid");
    const completed = completeSsnFlow(flow, "completed");

    expect(completed.requestId).toBe(flow.requestId);
  });
});

describe("SSN Flow — end-to-end createRequest + provideSsn sequence", () => {
  it("full happy path: created → ssn_provided → completed", () => {
    // Step 1: Create
    const flow = createSsnFlowRequest("job_e2e_001");
    expect(flow.state).toBe("created");
    expect(flow.ssn).toBeNull();

    // Step 2: Provide SSN
    const withSsn = provideSsnToFlow(flow, "456-78-9012");
    expect(withSsn.state).toBe("ssn_provided");
    expect(withSsn.ssn).toBe("456-78-9012");
    expect(withSsn.ssnProvidedAt).not.toBeNull();

    // Step 3: Complete
    const completed = completeSsnFlow(withSsn, "completed");
    expect(completed.state).toBe("completed");
    expect(completed.completedAt).not.toBeNull();
    expect(completed.ssn).toBe("456-78-9012");
  });

  it("full path: created → invalid SSN → failed", () => {
    const flow = createSsnFlowRequest("job_e2e_002");
    const failed = provideSsnToFlow(flow, "123-45-0000");
    expect(failed.state).toBe("failed");
    expect(failed.error).toContain("Invalid SSN");
  });

  it("timeout path: created → timeout (no SSN provided)", () => {
    const flow = createSsnFlowRequest("job_e2e_003");
    // Simulate: time passes, flow times out
    flow.timeoutAt = new Date(Date.now() - 100);
    expect(isSsnFlowTimedOut(flow)).toBe(true);

    const timedOut = completeSsnFlow(flow, "timeout");
    expect(timedOut.state).toBe("timeout");
  });

  it("SSN is normalized consistently through the flow", () => {
    const flow = createSsnFlowRequest("job_norm");
    const cases = ["123456789", "123 45 6789", "  123-45-6789  "];

    for (const raw of cases) {
      const result = provideSsnToFlow(flow, raw);
      expect(result.ssn).toBe("123-45-6789");
      expect(result.state).toBe("ssn_provided");
    }
  });
});

