379	  async start(): Promise<void> {
380	    if (this._started) return;
381	    this._started = true;
382	
383	    for (let i = 0; i < this._numWorkers; i++) {
384	      this._workers.push(
385	        new CreditScoreWorker({
386	          workerId: i,
387	          safeTestMode: this._safeTestMode,
388	          proxyCountry: this._proxyCountry,
389	          browserPool: this._browserPool,
390	        }),
391	      );
392	      this._running.push(false);
393	      this._dispatch({ type: "worker.started", workerId: i });
394	    }
395	
396	    // Start worker coroutines
397	    for (let i = 0; i < this._numWorkers; i++) {
398	      void this._workerLoop(i);
399	    }
400	  }
401	
402	  async stop(): Promise<void> {
403	    this._started = false;
404	    for (let i = 0; i < this._running.length; i++) {
405	      this._running[i] = false;
406	    }
407	    await this._browserPool.shutdown();
408	  }
